export enum UserRole {
  TENANT = 'TENANT',
  CARETAKER = 'CARETAKER',
  LANDLORD = 'LANDLORD'
}

export enum HouseStatus {
  VACANT = 'VACANT',
  RENTED = 'RENTED',
  UNDER_REPAIR = 'UNDER_REPAIR'
}

export interface Bill {
  rent: number;
  water: number;
  garbage: number;
  total: number;
  status: 'PAID' | 'UNPAID' | 'PARTIAL';
}

export interface Tenant {
  id: string;
  name: string;
  houseNumber: string;
  idNumber: string;
  phoneNumber: string;
  nextOfKin: string;
  agreementUrl?: string;
  bills: Bill;
  joinDate: string;
}

export interface House {
  id: string;
  houseNumber: string;
  type: 'Studio' | '1 Bedroom' | '2 Bedroom' | 'Penthouse';
  status: HouseStatus;
  lastVacantDate: string;
  repairs: Repair[];
}

export interface Repair {
  id: string;
  date: string;
  description: string;
  cost: number;
  category: string;
}

export interface PaymentRecord {
  id: string;
  tenantId: string;
  amount: number;
  date: string;
  type: 'RENT' | 'WATER' | 'GARBAGE' | 'TOTAL';
  reference: string;
}

