import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateTenantNotification = async (tenantName: string, amount: number) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Draft a polite but firm SMS/WhatsApp reminder for a tenant named ${tenantName} who has an outstanding balance of KES ${amount}. Mention that payments should be made via M-Pesa. Keep it under 160 characters.`,
  });
  return response.text;
};

export const analyzePropertyHealth = async (houses: any[], expenses: any[]) => {
  const prompt = `Analyze this property data and provide a short 2-sentence summary of property performance and maintenance needs:
  Houses: ${JSON.stringify(houses)}
  Expenses: ${JSON.stringify(expenses)}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });
  return response.text;
};

import React, { useState, useEffect } from 'react';
import { UserRole, Tenant, House, PaymentRecord } from './types';
import { INITIAL_TENANTS, INITIAL_HOUSES } from './constants';
import { Layout } from './components/Layout';
import { TenantDashboard } from './components/TenantDashboard';
import { CaretakerDashboard } from './components/CaretakerDashboard';
import { LandlordDashboard } from './components/LandlordDashboard';
import { LogIn, Users, ShieldCheck, Home } from 'lucide-react';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [tenants, setTenants] = useState<Tenant[]>(INITIAL_TENANTS);
  const [houses, setHouses] = useState<House[]>(INITIAL_HOUSES);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);

  // Simulation of persistent data
  const handleAddTenant = (newTenant: Tenant) => {
    setTenants(prev => [...prev, newTenant]);
    setHouses(prev => prev.map(h => h.houseNumber === newTenant.houseNumber ? { ...h, status: 'RENTED' as any } : h));
  };

  const handleUpdateBills = (tenantId: string, water: number) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        const newTotal = t.bills.rent + water + t.bills.garbage;
        return { ...t, bills: { ...t.bills, water, total: newTotal, status: 'UNPAID' } };
      }
      return t;
    }));
  };

  const handlePayment = (payment: PaymentRecord) => {
    setPayments(prev => [payment, ...prev]);
    setTenants(prev => prev.map(t => {
      if (t.id === payment.tenantId) {
        const remaining = t.bills.total - payment.amount;
        return { 
          ...t, 
          bills: { 
            ...t.bills, 
            total: remaining, 
            status: remaining <= 0 ? 'PAID' : 'PARTIAL' 
          } 
        };
      }
      return t;
    }));
  };

  const handleHouseUpdate = (houseId: string, status: any) => {
    setHouses(prev => prev.map(h => h.id === houseId ? { ...h, status } : h));
  };

  if (!role) {
    return (
      <div className="min-h-screen bg-[#0f172a] flex flex-col items-center justify-center p-6 text-white">
        <div className="mb-12 text-center">
          <h1 className="text-5xl font-royal mb-2 text-amber-400">ROYAL FLATS</h1>
          <p className="text-slate-400 uppercase tracking-widest text-sm">Property Management Excellence</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full max-w-4xl">
          <RoleCard 
            title="Tenant" 
            icon={<Home className="w-8 h-8"/>} 
            description="View balances, pay bills, and request service."
            onClick={() => setRole(UserRole.TENANT)}
          />
          <RoleCard 
            title="Caretaker" 
            icon={<ShieldCheck className="w-8 h-8"/>} 
            description="Manage units, tenants, and maintenance."
            onClick={() => setRole(UserRole.CARETAKER)}
            highlight
          />
          <RoleCard 
            title="Landlord" 
            icon={<Users className="w-8 h-8"/>} 
            description="Monitor finances and portfolio analytics."
            onClick={() => setRole(UserRole.LANDLORD)}
          />
        </div>
      </div>
    );
  }

  return (
    <Layout role={role} onLogout={() => setRole(null)}>
      {role === UserRole.TENANT && (
        <TenantDashboard 
          tenant={tenants[0]} 
          payments={payments.filter(p => p.tenantId === tenants[0].id)}
          onPay={handlePayment}
        />
      )}
      {role === UserRole.CARETAKER && (
        <CaretakerDashboard 
          tenants={tenants} 
          houses={houses}
          onAddTenant={handleAddTenant}
          onUpdateBills={handleUpdateBills}
          onUpdateHouse={handleHouseUpdate}
        />
      )}
      {role === UserRole.LANDLORD && (
        <LandlordDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
        />
      )}
    </Layout>
  );
};

const RoleCard: React.FC<{ title: string, icon: React.ReactNode, description: string, onClick: () => void, highlight?: boolean }> = ({ title, icon, description, onClick, highlight }) => (
  <button 
    onClick={onClick}
    className={`p-8 rounded-2xl border transition-all duration-300 text-left group
      ${highlight 
        ? 'border-amber-400/30 bg-amber-400/5 hover:bg-amber-400/10' 
        : 'border-slate-700 bg-slate-800/50 hover:bg-slate-800 hover:border-slate-500'}`}
  >
    <div className={`mb-4 p-3 rounded-lg inline-block ${highlight ? 'text-amber-400' : 'text-slate-400'} group-hover:scale-110 transition-transform`}>
      {icon}
    </div>
    <h3 className="text-xl font-bold mb-2">{title}</h3>
    <p className="text-slate-400 text-sm">{description}</p>
  </button>
);

export default App;

