import React, { useState } from 'react';
import { Tenant, PaymentRecord } from '../types';
import { CreditCard, History, Phone, MessageSquare, CheckCircle, Wallet } from 'lucide-react';

interface Props {
  tenant: Tenant;
  payments: PaymentRecord[];
  onPay: (payment: PaymentRecord) => void;
}

export const TenantDashboard: React.FC<Props> = ({ tenant, payments, onPay }) => {
  const [isPaying, setIsPaying] = useState(false);
  const [paymentAmount, setPaymentAmount] = useState(tenant.bills.total);

  const simulatePayment = () => {
    setIsPaying(true);
    setTimeout(() => {
      onPay({
        id: `pay-${Date.now()}`,
        tenantId: tenant.id,
        amount: paymentAmount,
        date: new Date().toISOString(),
        type: 'TOTAL',
        reference: `MPESA-${Math.random().toString(36).substring(7).toUpperCase()}`
      });
      setIsPaying(false);
      alert('Payment Successful! Thank you for choosing Royal Flats.');
    }, 2000);
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="col-span-2 space-y-6">
          <h2 className="text-2xl font-royal text-slate-800">Welcome, {tenant.name}</h2>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <BalanceCard title="Current Balance" amount={tenant.bills.total} icon={<Wallet className="text-amber-500" />} highlight />
            <BalanceCard title="House Rent" amount={tenant.bills.rent} icon={<CreditCard className="text-blue-500" />} />
            <BalanceCard title="Water Bill" amount={tenant.bills.water} icon={<div className="w-2 h-2 rounded-full bg-cyan-400" />} />
            <BalanceCard title="Garbage Fee" amount={tenant.bills.garbage} icon={<div className="w-2 h-2 rounded-full bg-green-400" />} />
          </div>

          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
              <History size={20} className="text-amber-500" /> Payment History
            </h3>
            {payments.length === 0 ? (
              <p className="text-slate-400 italic">No recent transactions found.</p>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="border-b text-slate-400 text-sm">
                      <th className="pb-3 font-medium">Date</th>
                      <th className="pb-3 font-medium">Ref No.</th>
                      <th className="pb-3 font-medium">Type</th>
                      <th className="pb-3 font-medium text-right">Amount (KES)</th>
                    </tr>
                  </thead>
                  <tbody>
                    {payments.map(p => (
                      <tr key={p.id} className="border-b last:border-0 hover:bg-slate-50 transition-colors">
                        <td className="py-4 text-sm">{new Date(p.date).toLocaleDateString()}</td>
                        <td className="py-4 text-sm font-mono text-slate-500">{p.reference}</td>
                        <td className="py-4 text-sm font-medium">{p.type}</td>
                        <td className="py-4 text-sm font-bold text-right text-emerald-600">-{p.amount.toLocaleString()}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-slate-900 text-white p-6 rounded-2xl shadow-xl overflow-hidden relative">
            <div className="absolute top-0 right-0 p-4 opacity-10">
              <CreditCard size={120} />
            </div>
            <h3 className="text-xl font-royal mb-2 text-amber-400">Lipa na M-Pesa</h3>
            <p className="text-slate-400 text-xs mb-6 uppercase tracking-widest">Secure Payment Portal</p>

            <div className="space-y-4">
              <div>
                <label className="text-xs text-slate-400 block mb-1">Enter Amount</label>
                <input 
                  type="number" 
                  value={paymentAmount}
                  onChange={(e) => setPaymentAmount(Number(e.target.value))}
                  className="bg-slate-800 border border-slate-700 w-full p-3 rounded-lg text-amber-400 font-bold outline-none focus:border-amber-500 transition-colors"
                />
              </div>
              <button 
                onClick={simulatePayment}
                disabled={isPaying || paymentAmount <= 0}
                className="w-full bg-[#32ba43] hover:bg-[#2da33b] disabled:opacity-50 text-white font-bold py-4 rounded-xl shadow-lg transition-transform active:scale-95 flex items-center justify-center gap-2"
              >
                {isPaying ? 'Processing...' : (
                  <>
                    <CheckCircle size={20} /> Pay via M-Pesa
                  </>
                )}
              </button>
            </div>
            <p className="mt-4 text-[10px] text-slate-500 text-center">Powered by Daraja API & Safaricom</p>
          </div>

          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
            <h3 className="font-bold mb-4">Contact Management</h3>
            <div className="space-y-3">
              <ContactButton icon={<Phone size={18}/>} label="Call Caretaker" color="bg-blue-50 text-blue-600" />
              <ContactButton icon={<MessageSquare size={18}/>} label="Text Caretaker" color="bg-amber-50 text-amber-600" />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const BalanceCard: React.FC<{ title: string, amount: number, icon: React.ReactNode, highlight?: boolean }> = ({ title, amount, icon, highlight }) => (
  <div className={`p-4 rounded-xl border transition-all ${highlight ? 'bg-amber-50 border-amber-200' : 'bg-white border-slate-100 shadow-sm'}`}>
    <div className="flex justify-between items-start mb-2">
      <span className="text-xs font-semibold text-slate-500 uppercase">{title}</span>
      {icon}
    </div>
    <div className="text-2xl font-bold text-slate-800">
      <span className="text-sm font-normal text-slate-400 mr-1">KES</span>
      {amount.toLocaleString()}
    </div>
  </div>
);

const ContactButton: React.FC<{ icon: React.ReactNode, label: string, color: string }> = ({ icon, label, color }) => (
  <button className={`w-full flex items-center justify-center gap-2 p-3 rounded-xl font-medium transition-transform active:scale-95 ${color}`}>
    {icon} {label}
  </button>
);

import React, { useState } from 'react';
import { Tenant, House, HouseStatus } from '../types';
import { UserPlus, Droplets, Send, Tool, RefreshCw, ChevronRight, MessageCircle } from 'lucide-react';
import { generateTenantNotification } from '../services/geminiService';

interface Props {
  tenants: Tenant[];
  houses: House[];
  onAddTenant: (t: Tenant) => void;
  onUpdateBills: (id: string, water: number) => void;
  onUpdateHouse: (id: string, status: HouseStatus) => void;
}

export const CaretakerDashboard: React.FC<Props> = ({ tenants, houses, onAddTenant, onUpdateBills, onUpdateHouse }) => {
  const [activeTab, setActiveTab] = useState<'houses' | 'tenants' | 'billing'>('houses');
  const [showAddModal, setShowAddModal] = useState(false);
  const [loadingAI, setLoadingAI] = useState<string | null>(null);

  const handleSendReminder = async (tenant: Tenant) => {
    setLoadingAI(tenant.id);
    try {
      const message = await generateTenantNotification(tenant.name, tenant.bills.total);
      alert(`AI Draft Notification for ${tenant.name}:\n\n"${message}"\n\nNotification sent to ${tenant.phoneNumber}`);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingAI(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <h2 className="text-2xl font-royal text-slate-800">Caretaker Operations</h2>
        <div className="flex bg-slate-200 p-1 rounded-lg">
          {(['houses', 'tenants', 'billing'] as const).map(tab => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === tab ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'houses' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {houses.map(house => (
            <div key={house.id} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm hover:border-amber-300 transition-all group">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h3 className="text-xl font-bold text-slate-800">{house.houseNumber}</h3>
                  <p className="text-xs text-slate-400 font-medium">{house.type}</p>
                </div>
                <StatusBadge status={house.status} />
              </div>
              <div className="space-y-3 mb-4 text-sm text-slate-600">
                <div className="flex justify-between">
                  <span>Last Vacant</span>
                  <span className="font-medium">{house.lastVacantDate}</span>
                </div>
                <div className="flex justify-between">
                  <span>Repairs Done</span>
                  <span className="font-medium">{house.repairs.length} items</span>
                </div>
              </div>
              <div className="flex gap-2">
                <select 
                  className="flex-1 bg-slate-50 border text-xs p-2 rounded-lg outline-none"
                  value={house.status}
                  onChange={(e) => onUpdateHouse(house.id, e.target.value as HouseStatus)}
                >
                  {Object.values(HouseStatus).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
                <button className="p-2 bg-slate-100 text-slate-500 rounded-lg hover:bg-slate-200">
                  <Tool size={16} />
                </button>
              </div>
            </div>
          ))}
          <button 
            onClick={() => setShowAddModal(true)}
            className="border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center p-8 text-slate-400 hover:border-amber-400 hover:text-amber-500 transition-all group"
          >
            <UserPlus size={40} className="mb-2 group-hover:scale-110 transition-transform" />
            <span className="font-bold">Register New Tenant</span>
          </button>
        </div>
      )}

      {activeTab === 'tenants' && (
        <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Tenant Details</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">House</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase">Payment Status</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {tenants.map(t => (
                <tr key={t.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-800">{t.name}</div>
                    <div className="text-xs text-slate-400">{t.phoneNumber}</div>
                  </td>
                  <td className="px-6 py-4 font-medium text-slate-600">{t.houseNumber}</td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${t.bills.status === 'PAID' ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                      {t.bills.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={() => handleSendReminder(t)}
                      disabled={loadingAI === t.id}
                      className="inline-flex items-center gap-2 bg-amber-500 hover:bg-amber-600 text-white px-3 py-1.5 rounded-lg text-xs font-bold disabled:opacity-50"
                    >
                      {loadingAI === t.id ? 'Thinking...' : <><Send size={14}/> Notify</>}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {activeTab === 'billing' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
            <h3 className="text-lg font-bold mb-6 flex items-center gap-2">
              <Droplets className="text-blue-500" /> Update Water Readings
            </h3>
            <div className="space-y-4">
              {tenants.map(t => (
                <div key={t.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-xl">
                  <div>
                    <div className="font-bold">{t.houseNumber} - {t.name}</div>
                    <div className="text-xs text-slate-400">Current: KES {t.bills.water}</div>
                  </div>
                  <div className="flex items-center gap-2">
                    <input 
                      type="number" 
                      placeholder="New Reading" 
                      className="w-24 p-2 text-sm border rounded-lg"
