}

export const LandlordDashboard: React.FC<Props> = ({ tenants, houses, payments }) => {
  const totalRent = tenants.reduce((acc, t) => acc + t.bills.rent, 0);
  const totalPaid = payments.reduce((acc, p) => acc + p.amount, 0);
  const occupancyRate = (houses.filter(h => h.status === HouseStatus.RENTED).length / houses.length) * 100;

  const occupancyData = [
    { name: 'Occupied', value: houses.filter(h => h.status === HouseStatus.RENTED).length },
    { name: 'Vacant', value: houses.filter(h => h.status === HouseStatus.VACANT).length },
    { name: 'Repair', value: houses.filter(h => h.status === HouseStatus.UNDER_REPAIR).length },
  ];

  const financialData = [
    { name: 'Expected', amount: totalRent },
    { name: 'Collected', amount: totalPaid },
    { name: 'Pending', amount: Math.max(0, totalRent - totalPaid) },
  ];

  const COLORS = ['#10b981', '#f59e0b', '#ef4444'];

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Total Expected Revenue" value={`KES ${totalRent.toLocaleString()}`} icon={<DollarSign className="text-blue-500" />} change="+12%" />
        <StatCard title="Total Collected" value={`KES ${totalPaid.toLocaleString()}`} icon={<TrendingUp className="text-emerald-500" />} change="+5%" />
        <StatCard title="Occupancy Rate" value={`${occupancyRate.toFixed(1)}%`} icon={<Home className="text-amber-500" />} change="Stable" />
        <StatCard title="Active Tenants" value={tenants.length.toString()} icon={<Users className="text-purple-500" />} change="+2 new" />
