const StatusToggleButton: React.FC<{ active: boolean, onClick: () => void, icon: React.ReactNode, color: 'emerald' | 'amber' | 'rose', label: string }> = ({ active, onClick, icon, color, label }) => {
  const colorMap = {
    emerald: active ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-200' : 'text-slate-400 hover:text-emerald-500 hover:bg-emerald-50',
    amber: active ? 'bg-amber-500 text-white shadow-lg shadow-amber-200' : 'text-slate-400 hover:text-amber-500 hover:bg-amber-50',
    rose: active ? 'bg-rose-500 text-white shadow-lg shadow-rose-200' : 'text-slate-400 hover:text-rose-500 hover:bg-rose-50',
  };

  return (
    <button 
      onClick={onClick}
      className={`flex flex-col items-center justify-center py-2.5 rounded-lg transition-all gap-1 ${colorMap[color]}`}
    >
      {icon}
      <span className="text-[8px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );
};

const InputGroup: React.FC<{ icon: React.ReactNode, label: string, placeholder: string, value: string, onChange: (val: string) => void, type?: string }> = ({ icon, label, placeholder, value, onChange, type = 'text' }) => (
  <div className="space-y-1.5">
    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
      {icon} {label}
    </label>
    <input 
      type={type}
      required
      placeholder={placeholder}
      className="w-full bg-slate-50 border-2 border-slate-100 p-3 rounded-2xl focus:border-amber-400 outline-none transition-all placeholder:text-slate-300 text-sm font-medium"
      value={value}
      onChange={(e) => onChange(e.target.value)}
    />
  </div>
);

const StatusBadge: React.FC<{ status: HouseStatus }> = ({ status }) => {
  const config = {
    [HouseStatus.RENTED]: { bg: 'bg-emerald-50', text: 'text-emerald-700', border: 'border-emerald-200', dot: 'bg-emerald-500' },
    [HouseStatus.VACANT]: { bg: 'bg-amber-50', text: 'text-amber-700', border: 'border-amber-200', dot: 'bg-amber-500' },
    [HouseStatus.UNDER_REPAIR]: { bg: 'bg-rose-50', text: 'text-rose-700', border: 'border-rose-200', dot: 'bg-rose-500' }
  };
  const theme = config[status];
  return (
    <span className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-black uppercase tracking-wider border ${theme.bg} ${theme.text} ${theme.border}`}>
      <span className={`w-1.5 h-1.5 rounded-full ${theme.dot} animate-pulse`} />
      {status.replace('_', ' ')}
    </span>
  );
};

const MaintenanceItem: React.FC<{ date: string, task: string, cost: number, house: string }> = ({ date, task, cost, house }) => (
  <div className="flex items-center justify-between p-4 bg-slate-800/50 rounded-2xl border border-slate-800 hover:border-slate-700 transition-colors">
