import React, { useState, useEffect } from 'react';
import { UserRole, Tenant, House, PaymentRecord } from './types';
import { INITIAL_TENANTS, INITIAL_HOUSES } from './constants';
import { Layout } from './components/Layout';
import { CaretakerDashboard } from './components/CaretakerDashboard';
import { LandlordDashboard } from './components/LandlordDashboard';
import { Users, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [tenants, setTenants] = useState<Tenant[]>(INITIAL_TENANTS);
  const [houses, setHouses] = useState<House[]>(INITIAL_HOUSES);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);

  // Simulation of persistent data
  const handleAddTenant = (newTenant: Tenant) => {
    setTenants(prev => [...prev, newTenant]);
    setHouses(prev => prev.map(h => h.houseNumber === newTenant.houseNumber ? { ...h, status: 'RENTED' as any } : h));
  };

  const handleUpdateBills = (tenantId: string, water: number) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        const newTotal = t.bills.rent + water + t.bills.garbage;
        return { ...t, bills: { ...t.bills, water, total: newTotal, status: 'UNPAID' } };
      }
      return t;
    }));
  };

  const handlePayment = (payment: PaymentRecord) => {
    setPayments(prev => [payment, ...prev]);
    setTenants(prev => prev.map(t => {
      if (t.id === payment.tenantId) {
        const bills = { ...t.bills };

        // Granular deduction based on payment type
        if (payment.type === 'RENT') {
          bills.rent = Math.max(0, bills.rent - payment.amount);
        } else if (payment.type === 'WATER') {
          bills.water = Math.max(0, bills.water - payment.amount);
        } else if (payment.type === 'GARBAGE') {
          bills.garbage = Math.max(0, bills.garbage - payment.amount);
        } else {
          // If paying TOTAL, we distribute the amount across categories
          let rem = payment.amount;
          const waterPay = Math.min(rem, bills.water);
          bills.water -= waterPay;
          rem -= waterPay;

          const garbagePay = Math.min(rem, bills.garbage);
          bills.garbage -= garbagePay;
          rem -= garbagePay;

          bills.rent = Math.max(0, bills.rent - rem);
        }

        // Recalculate total and status
        bills.total = bills.rent + bills.water + bills.garbage;
        bills.status = bills.total <= 0 ? 'PAID' : 'PARTIAL';

        return { ...t, bills };
      }
      return t;
    }));
  };

  const handleHouseUpdate = (houseId: string, status: any) => {
    setHouses(prev => prev.map(h => h.id === houseId ? { ...h, status } : h));
  };

  if (!role) {
    return (
      <div className="min-h-screen bg-[#0f172a] flex flex-col items-center justify-center p-6 text-white">
        <div className="mb-12 text-center animate-fadeIn">
          <h1 className="text-5xl font-royal mb-2 text-amber-400">ROYAL FLATS</h1>
          <p className="text-slate-400 uppercase tracking-widest text-sm">Property Management Excellence</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full max-w-2xl animate-slideUp">
          <RoleCard 
            title="Caretaker" 
            icon={<ShieldCheck className="w-10 h-10"/>} 
            description="Manage units, residents, and maintain property integrity."
            onClick={() => setRole(UserRole.CARETAKER)}
            highlight
          />
          <RoleCard 
            title="Landlord" 
            icon={<Users className="w-10 h-10"/>} 
            description="Access financial insights and global property analytics."
            onClick={() => setRole(UserRole.LANDLORD)}
          />
        </div>
      </div>
    );
  }

  return (
    <Layout role={role} onLogout={() => setRole(null)}>
      {role === UserRole.CARETAKER && (
        <CaretakerDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
          onAddTenant={handleAddTenant}
          onUpdateBills={handleUpdateBills}
          onUpdateHouse={handleHouseUpdate}
        />
      )}
      {role === UserRole.LANDLORD && (
        <LandlordDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
        />
      )}
    </Layout>
  );
};

const RoleCard: React.FC<{ title: string, icon: React.ReactNode, description: string, onClick: () => void, highlight?: boolean }> = ({ title, icon, description, onClick, highlight }) => (
  <button 
