/**
 * TENANT INTELLIGENCE MODAL
 * A comprehensive deep-dive into a tenant's financial health and history.
 */
const TenantIntelligenceModal: React.FC<{ tenant: Tenant, payments: PaymentRecord[], onClose: () => void }> = ({ tenant, payments, onClose }) => {
  const [activeTab, setActiveTab] = useState<'analytics' | 'ledger' | 'profile'>('analytics');
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);

  // Derived Financial Data
  const financialMetrics = useMemo(() => {
    const totalPaid = payments.reduce((acc, p) => acc + p.amount, 0);
    const totalDue = totalPaid + tenant.bills.total;
    const paymentRate = totalDue > 0 ? (totalPaid / totalDue) * 100 : 100;

    // Monthly grouping for chart
    const monthlyData: Record<string, number> = {};
    payments.forEach(p => {
      const month = new Date(p.date).toLocaleString('default', { month: 'short' });
      monthlyData[month] = (monthlyData[month] || 0) + p.amount;
    });

    const chartData = Object.entries(monthlyData).map(([name, amount]) => ({ name, amount }));

    // Running balance calculation for ledger
    let runningBalance = totalDue;
    const ledgerItems = [...payments]
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .map(p => {
        const item = { ...p, balanceAfter: runningBalance - p.amount };
        runningBalance -= p.amount;
        return item;
      })
      .reverse();

    return { totalPaid, totalDue, paymentRate, chartData, ledgerItems };
  }, [payments, tenant]);

  const handleRunAnalysis = async () => {
    setLoadingAI(true);
    try {
      const insight = await analyzeTenantFinancials(tenant.name, tenant.bills, payments);
      setAiInsight(insight);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingAI(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-fadeIn">
      <div className="bg-white w-full max-w-5xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[92vh] animate-slideUp">
        {/* Modal Header */}
        <div className="bg-slate-900 p-10 text-white relative">
          <div className="absolute top-0 right-0 p-10 opacity-5"><User size={140} /></div>
          <div className="flex justify-between items-start relative z-10">
            <div>
              <div className="flex items-center gap-3 mb-3">
                <span className="bg-amber-500 text-white text-[10px] font-black uppercase tracking-[0.2em] px-2.5 py-1 rounded">Resident Intel</span>
                <BillStatusBadge status={tenant.bills.status} />
              </div>
              <h2 className="text-5xl font-royal text-amber-400">{tenant.name}</h2>
              <div className="flex items-center gap-4 mt-4 text-slate-400 text-sm font-medium">
                <div className="flex items-center gap-1.5"><Home size={16}/> Unit {tenant.houseNumber}</div>
                <div className="w-1.5 h-1.5 rounded-full bg-slate-700" />
                <div className="flex items-center gap-1.5"><Clock size={16}/> Resident since {tenant.joinDate}</div>
              </div>
            </div>
            <button onClick={onClose} className="p-4 bg-white/10 hover:bg-white/20 rounded-full transition-all group">
              <X size={24} className="group-hover:rotate-90 transition-transform" />
            </button>
          </div>

          <div className="flex gap-4 mt-10">
            <TabButton active={activeTab === 'analytics'} onClick={() => setActiveTab('analytics')} icon={<BarChart3 size={16}/>} label="Financial Analytics" />
            <TabButton active={activeTab === 'ledger'} onClick={() => setActiveTab('ledger')} icon={<Receipt size={16}/>} label="Payment Ledger" />
            <TabButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<ShieldAlert size={16}/>} label="Risk Profile" />
          </div>
        </div>

        {/* Modal Content */}
        <div className="flex-1 overflow-y-auto p-12 bg-slate-50">
          {activeTab === 'analytics' && (
            <div className="space-y-10">
              {/* Summary Stats */}
              <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                <MetricCard label="Current Debt" value={`KES ${tenant.bills.total.toLocaleString()}`} icon={<TrendingDown className="text-rose-500"/>} subtext="Outstanding Balance" trend="warning" />
                <MetricCard label="Lifetime Paid" value={`KES ${financialMetrics.totalPaid.toLocaleString()}`} icon={<TrendingUp className="text-emerald-500"/>} subtext="Cumulative Payments" trend="success" />
                <MetricCard label="Payment Rate" value={`${financialMetrics.paymentRate.toFixed(1)}%`} icon={<Activity className="text-blue-500"/>} subtext="Collection Efficiency" />
                <MetricCard label="Next Bill" value="1st Oct" icon={<Clock className="text-amber-500"/>} subtext="Upcoming Cycle" />
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
                <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                  <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-8">Monthly Payment Volume</h4>
                  <div className="h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={financialMetrics.chartData}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fill: '#94a3b8' }} />
                        <YAxis hide />
                        <Tooltip cursor={{ fill: '#f8fafc' }} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                        <Bar dataKey="amount" radius={[8, 8, 0, 0]} barSize={40}>
                          {financialMetrics.chartData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={index === financialMetrics.chartData.length - 1 ? '#f59e0b' : '#1e293b'} />
                          ))}
                        </Bar>
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
                </div>

                <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white flex flex-col justify-between">
                  <div>
                    <h4 className="text-[10px] font-black text-amber-400 uppercase tracking-[0.2em] mb-6">Bill Composition</h4>
                    <div className="space-y-6">
