                      <BillComponent label="Water Utility" amount={tenant.bills.water} total={tenant.bills.total} color="bg-blue-400" />
                      <BillComponent label="Garbage Collection" amount={tenant.bills.garbage} total={tenant.bills.total} color="bg-emerald-400" />
                    </div>
                  </div>
                  <div className="pt-10 border-t border-slate-800">
                    <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Total Current Owed</div>
                    <div className="text-3xl font-royal text-white font-black">KES {tenant.bills.total.toLocaleString()}</div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'ledger' && (
            <div className="space-y-6">
              <div className="flex justify-between items-center mb-6">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Detailed Transaction History</h4>
