import React, { useState } from 'react';
import { Tenant, House, PaymentRecord, HouseStatus } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid } from 'recharts';
import { TrendingUp, Users, DollarSign, Home, AlertCircle, Clock, CheckCircle2, AlertTriangle, Search, Activity, History, X, User, Eye } from 'lucide-react';
import { analyzeTenantFinancials } from '../services/geminiService';

interface Props {
  tenants: Tenant[];
  houses: House[];
  payments: PaymentRecord[];
}

export const LandlordDashboard: React.FC<Props> = ({ tenants, houses, payments }) => {
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const totalRent = tenants.reduce((acc, t) => acc + t.bills.rent, 0);
  const totalPaid = payments.reduce((acc, p) => acc + p.amount, 0);
  const occupancyRate = (houses.length > 0) ? (houses.filter(h => h.status === HouseStatus.RENTED).length / houses.length) * 100 : 0;

  const occupancyData = [
    { name: 'Occupied', value: houses.filter(h => h.status === HouseStatus.RENTED).length },
    { name: 'Vacant', value: houses.filter(h => h.status === HouseStatus.VACANT).length },
    { name: 'Repair', value: houses.filter(h => h.status === HouseStatus.UNDER_REPAIR).length },
  ];

  const financialData = [
    { name: 'Expected', amount: totalRent },
    { name: 'Collected', amount: totalPaid },
    { name: 'Pending', amount: Math.max(0, totalRent - totalPaid) },
  ];

  const COLORS = ['#10b981', '#f59e0b', '#ef4444'];

  return (
    <div className="space-y-8">
      {selectedTenant && (
        <TenantIntelligenceModal 
          tenant={selectedTenant} 
          payments={payments.filter(p => p.tenantId === selectedTenant.id)}
          onClose={() => setSelectedTenant(null)}
        />
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Total Expected Revenue" value={`KES ${totalRent.toLocaleString()}`} icon={<DollarSign className="text-blue-500" />} change="+12%" />
        <StatCard title="Total Collected" value={`KES ${totalPaid.toLocaleString()}`} icon={<TrendingUp className="text-emerald-500" />} change="+5%" />
        <StatCard title="Occupancy Rate" value={`${occupancyRate.toFixed(1)}%`} icon={<Home className="text-amber-500" />} change="Stable" />
        <StatCard title="Active Tenants" value={tenants.length.toString()} icon={<Users className="text-purple-500" />} change="+2 new" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h3 className="text-lg font-bold mb-6">Financial Overview</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={financialData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="amount" radius={[4, 4, 0, 0]}>
                  {financialData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h3 className="text-lg font-bold mb-6">Occupancy Status</h3>
          <div className="h-[300px] w-full flex items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={occupancyData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {occupancyData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div className="flex flex-col gap-2 ml-4">
              {occupancyData.map((item, idx) => (
                <div key={item.name} className="flex items-center gap-2 text-xs">
                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[idx] }} />
                  <span className="text-slate-500">{item.name}: <b>{item.value}</b></span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
        <h3 className="text-lg font-bold mb-6">Detailed Tenant Audit</h3>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="border-b bg-slate-50">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500">Tenant</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500">Unit</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500">Rent Status</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500">Total Owed</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 text-right">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {tenants.map(t => (
                <tr key={t.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-800">{t.name}</div>
                    <div className="text-xs text-slate-400">ID: {t.idNumber}</div>
                  </td>
                  <td className="px-6 py-4 font-medium">{t.houseNumber}</td>
                  <td className="px-6 py-4">
                    <BillStatusBadge status={t.bills.status} />
                  </td>
                  <td className="px-6 py-4 font-bold text-slate-700">KES {t.bills.total.toLocaleString()}</td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={() => setSelectedTenant(t)}
                      className="p-2 bg-slate-100 hover:bg-amber-500 hover:text-white text-slate-500 rounded-xl transition-all"
                    >
                      <Eye size={16} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
