import React, { useState, useEffect } from 'react';
import { UserRole, Tenant, House, PaymentRecord, Expense } from './types';
import { INITIAL_TENANTS, INITIAL_HOUSES } from './constants';
import { Layout } from './components/Layout';
import { CaretakerDashboard } from './components/CaretakerDashboard';
import { LandlordDashboard } from './components/LandlordDashboard';
import { TenantDashboard } from './components/TenantDashboard';
import { Users, ShieldCheck, Key } from 'lucide-react';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [activeView, setActiveView] = useState<string>('dashboard');
  const [tenants, setTenants] = useState<Tenant[]>(INITIAL_TENANTS);
  const [houses, setHouses] = useState<House[]>(INITIAL_HOUSES);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  // Simulation of persistent data
  const handleAddTenant = (newTenant: Tenant) => {
    setTenants(prev => [...prev, newTenant]);
    setHouses(prev => prev.map(h => h.houseNumber === newTenant.houseNumber ? { ...h, status: 'RENTED' as any } : h));
  };

  const handleUpdateBills = (tenantId: string, water: number) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        const newTotal = t.bills.rent + water + t.bills.garbage;
        return { ...t, bills: { ...t.bills, water, total: newTotal, status: 'UNPAID' } };
      }
      return t;
    }));
  };

  const handlePayment = (payment: PaymentRecord) => {
    setPayments(prev => [payment, ...prev]);
    setTenants(prev => prev.map(t => {
      if (t.id === payment.tenantId) {
        const bills = { ...t.bills };

        if (payment.type === 'RENT') bills.rent = Math.max(0, bills.rent - payment.amount);
        else if (payment.type === 'WATER') bills.water = Math.max(0, bills.water - payment.amount);
        else if (payment.type === 'GARBAGE') bills.garbage = Math.max(0, bills.garbage - payment.amount);
        else {
          let rem = payment.amount;
          const waterPay = Math.min(rem, bills.water);
          bills.water -= waterPay;
          rem -= waterPay;
          const garbagePay = Math.min(rem, bills.garbage);
          bills.garbage -= garbagePay;
          rem -= garbagePay;
          bills.rent = Math.max(0, bills.rent - rem);
        }

        bills.total = bills.rent + bills.water + bills.garbage;
        bills.status = bills.total <= 0 ? 'PAID' : 'PARTIAL';
        return { ...t, bills };
      }
      return t;
    }));
  };

  const handleHouseUpdate = (houseId: string, status: any) => {
    setHouses(prev => prev.map(h => h.id === houseId ? { ...h, status } : h));
  };

  if (!role) {
    return (
      <div className="min-h-screen bg-[#0f172a] flex flex-col items-center justify-center p-6 text-white overflow-hidden relative">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(245,158,11,0.05),transparent)] pointer-events-none" />

        <div className="mb-12 text-center animate-fadeIn">
          <h1 className="text-7xl font-royal mb-4 text-amber-400 drop-shadow-2xl">ROYAL FLATS</h1>
          <p className="text-slate-400 uppercase tracking-[0.4em] text-xs font-black">Management Intelligence System</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 w-full max-w-5xl animate-slideUp">
          <RoleCard 
            title="Resident" 
            icon={<Key className="w-10 h-10"/>} 
            description="Access bills, make payments and track history."
            onClick={() => setRole(UserRole.TENANT)}
          />
          <RoleCard 
            title="Caretaker" 
            icon={<ShieldCheck className="w-10 h-10"/>} 
            description="Manage units, residents, and property maintenance."
            onClick={() => setRole(UserRole.CARETAKER)}
            highlight
          />
          <RoleCard 
            title="Owner" 
            icon={<Users className="w-10 h-10"/>} 
            description="Financial insights and global property analytics."
            onClick={() => setRole(UserRole.LANDLORD)}
          />
        </div>
      </div>
    );
  }

  return (
    <Layout 
      role={role} 
      onLogout={() => { setRole(null); setActiveView('dashboard'); }} 
      activeView={activeView} 
      onViewChange={setActiveView}
    >
      {role === UserRole.CARETAKER && (
        <CaretakerDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
          onAddTenant={handleAddTenant}
          onUpdateBills={handleUpdateBills}
          onUpdateHouse={handleHouseUpdate}
        />
      )}
      {role === UserRole.LANDLORD && (
        <LandlordDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
        />
      )}
      {role === UserRole.TENANT && (
        <TenantDashboard 
          tenant={tenants[0]} // Simulation: picking the first tenant
          payments={payments.filter(p => p.tenantId === tenants[0].id)}
          onPay={handlePayment}
        />
      )}
    </Layout>
  );
};

