import { INITIAL_TENANTS, INITIAL_HOUSES } from './constants';
import { Layout } from './components/Layout';
import { CaretakerDashboard } from './components/CaretakerDashboard';
import { LandlordDashboard } from './components/LandlordDashboard';
import { TenantDashboard } from './components/TenantDashboard';
import { Users, ShieldCheck, Key } from 'lucide-react';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [activeView, setActiveView] = useState<string>('dashboard');
  const [tenants, setTenants] = useState<Tenant[]>(INITIAL_TENANTS);
  const [houses, setHouses] = useState<House[]>(INITIAL_HOUSES);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);

  const handleAddTenant = (newTenant: Tenant) => {
    setTenants(prev => [...prev, newTenant]);
    setHouses(prev => prev.map(h => h.houseNumber === newTenant.houseNumber ? { ...h, status: 'RENTED' as any } : h));
  };

  const handleUpdateBills = (tenantId: string, water: number) => {
    setTenants(prev => prev.map(t => {
      if (t.id === tenantId) {
        const newTotal = t.bills.rent + water + t.bills.garbage;
        return { ...t, bills: { ...t.bills, water, total: newTotal, status: 'UNPAID' } };
      }
      return t;
    }));
  };

  const handlePayment = (payment: PaymentRecord) => {
    setPayments(prev => [payment, ...prev]);
    setTenants(prev => prev.map(t => {
      if (t.id === payment.tenantId) {
        const bills = { ...t.bills };
        if (payment.type === 'RENT') bills.rent = Math.max(0, bills.rent - payment.amount);
        else if (payment.type === 'WATER') bills.water = Math.max(0, bills.water - payment.amount);
        else if (payment.type === 'GARBAGE') bills.garbage = Math.max(0, bills.garbage - payment.amount);
        else {
          let rem = payment.amount;
          const waterPay = Math.min(rem, bills.water);
          bills.water -= waterPay;
          rem -= waterPay;
          const garbagePay = Math.min(rem, bills.garbage);
          bills.garbage -= garbagePay;
          rem -= garbagePay;
          bills.rent = Math.max(0, bills.rent - rem);
        }
        bills.total = bills.rent + bills.water + bills.garbage;
        bills.status = bills.total <= 0 ? 'PAID' : 'PARTIAL';
        return { ...t, bills };
      }
      return t;
    }));
  };

  const handleHouseUpdate = (houseId: string, status: any) => {
    setHouses(prev => prev.map(h => h.id === houseId ? { ...h, status } : h));
  };

  const renderContent = () => {
    if (role === UserRole.CARETAKER) {
      return (
        <CaretakerDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
          activeTab={activeView === 'dashboard' ? 'houses' : activeView as any}
          onAddTenant={handleAddTenant}
          onUpdateBills={handleUpdateBills}
          onUpdateHouse={handleHouseUpdate}
        />
      );
    }
    if (role === UserRole.LANDLORD) {
      return (
        <LandlordDashboard 
          tenants={tenants} 
          houses={houses}
          payments={payments}
          expenses={expenses}
          view={activeView}
        />
      );
    }
    if (role === UserRole.TENANT) {
      return (
        <TenantDashboard 
          tenant={tenants[0]} 
          payments={payments.filter(p => p.tenantId === tenants[0].id)}
          onPay={handlePayment}
        />
      );
    }
    return null;
  };

  if (!role) {
    return (
      <div className="min-h-screen bg-[#0f172a] flex flex-col items-center justify-center p-6 text-white overflow-hidden relative">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(245,158,11,0.05),transparent)] pointer-events-none" />
        <div className="mb-12 text-center animate-fadeIn">
          <h1 className="text-7xl font-royal mb-4 text-amber-400 drop-shadow-2xl">ROYAL FLATS</h1>
          <p className="text-slate-400 uppercase tracking-[0.4em] text-xs font-black">Management Intelligence System</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 w-full max-w-5xl animate-slideUp">
          <RoleCard title="Resident" icon={<Key className="w-10 h-10"/>} description="Access bills, make payments and track history." onClick={() => setRole(UserRole.TENANT)} />
          <RoleCard title="Caretaker" icon={<ShieldCheck className="w-10 h-10"/>} description="Manage units, residents, and property maintenance." onClick={() => setRole(UserRole.CARETAKER)} highlight />
          <RoleCard title="Owner" icon={<Users className="w-10 h-10"/>} description="Financial insights and global property analytics." onClick={() => setRole(UserRole.LANDLORD)} />
        </div>
      </div>
    );
  }

  return (
    <Layout 
      role={role} 
      onLogout={() => { setRole(null); setActiveView('dashboard'); }} 
      activeView={activeView} 
      onViewChange={setActiveView}
    >
      {renderContent()}
    </Layout>
  );
};

const RoleCard: React.FC<{ title: string, icon: React.ReactNode, description: string, onClick: () => void, highlight?: boolean }> = ({ title, icon, description, onClick, highlight }) => (
  <button onClick={onClick} className={`p-10 rounded-[2.5rem] border transition-all duration-500 text-left group relative overflow-hidden h-full flex flex-col ${highlight ? 'border-amber-400/30 bg-amber-400/5 hover:bg-amber-400/10 hover:border-amber-400 shadow-xl shadow-amber-900/10' : 'border-slate-700 bg-slate-800/50 hover:bg-slate-800 hover:border-slate-500 shadow-xl'}`}>
    <div className={`mb-8 p-5 rounded-2xl inline-block ${highlight ? 'bg-amber-400/20 text-amber-400' : 'bg-slate-700 text-slate-400'} group-hover:scale-110 transition-transform duration-500`}>{icon}</div>
    <h3 className="text-3xl font-royal mb-4 text-white">{title} Portal</h3>
    <p className="text-slate-400 text-sm leading-relaxed mb-8 flex-1">{description}</p>
    <div className="flex items-center text-[10px] font-black uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all duration-300 text-amber-500 transform translate-y-4 group-hover:translate-y-0">Access System &rarr;</div>
  </button>
);

export default App;

import React, { useState, useMemo } from 'react';
import { Tenant, House, PaymentRecord, Expense, HouseStatus } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid } from 'recharts';
import { TrendingUp, Users, DollarSign, Home, AlertCircle, Clock, CheckCircle2, AlertTriangle, Search, Activity, History, X, User, Eye, FileText, Download, Briefcase, Wallet } from 'lucide-react';
import { analyzeTenantFinancials, analyzePropertyHealth } from '../services/geminiService';

interface Props {
  tenants: Tenant[];
  houses: House[];
  payments: PaymentRecord[];
  expenses: Expense[];
  view: string;
}

export const LandlordDashboard: React.FC<Props> = ({ tenants, houses, payments, expenses, view }) => {
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [aiReport, setAiReport] = useState<string | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);

  const totalExpected = tenants.reduce((acc, t) => acc + t.bills.rent, 0);
  const totalCollected = payments.reduce((acc, p) => acc + p.amount, 0);
  const totalMaintenance = houses.reduce((acc, h) => acc + h.repairs.reduce((rAcc, r) => rAcc + r.cost, 0), 0);
  const occupancyRate = (houses.length > 0) ? (houses.filter(h => h.status === HouseStatus.RENTED).length / houses.length) * 100 : 0;

  const handleGenerateAIReport = async () => {
    setLoadingAI(true);
    try {
      const report = await analyzePropertyHealth(houses, expenses);
      setAiReport(report);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingAI(false);
    }
  };

  const occupancyData = [
    { name: 'Occupied', value: houses.filter(h => h.status === HouseStatus.RENTED).length },
    { name: 'Vacant', value: houses.filter(h => h.status === HouseStatus.VACANT).length },
    { name: 'Repair', value: houses.filter(h => h.status === HouseStatus.UNDER_REPAIR).length },
  ];

  const financialData = [
    { name: 'Expected', amount: totalExpected },
    { name: 'Collected', amount: totalCollected },
    { name: 'Expenses', amount: totalMaintenance },
  ];

  const COLORS = ['#10b981', '#f59e0b', '#ef4444'];

  if (view === 'reports') {
    return (
      <div className="space-y-8 animate-fadeIn">
        <div className="flex justify-between items-center">
          <h2 className="text-3xl font-royal text-slate-800">Financial Reports</h2>
          <button onClick={handleGenerateAIReport} disabled={loadingAI} className="flex items-center gap-2 bg-slate-900 text-white px-6 py-3 rounded-xl font-bold hover:bg-slate-800 transition-all shadow-xl">
            {loadingAI ? <Activity className="animate-spin" size={18}/> : <Briefcase size={18}/>}
            {loadingAI ? 'Analyzing...' : 'Generate AI Portfolio Audit'}
          </button>
        </div>

        {aiReport && (
          <div className="bg-amber-50 border border-amber-200 p-8 rounded-[2.5rem] relative overflow-hidden">
            <div className="absolute -top-10 -right-10 opacity-5 text-amber-500 rotate-12"><FileText size={160}/></div>
            <div className="flex items-center gap-3 mb-4">
              <span className="bg-amber-500 text-white text-[10px] font-black uppercase tracking-widest px-2 py-1 rounded">AI Insight</span>
            </div>
            <p className="text-xl font-royal text-amber-900 italic leading-relaxed">"{aiReport}"</p>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <ReportSection title="Rent Roll Summary" icon={<Wallet className="text-emerald-500"/>}>
             <div className="space-y-4">
               <ReportRow label="Total Expected Rent" value={`KES ${totalExpected.toLocaleString()}`} />
               <ReportRow label="Total Collected" value={`KES ${totalCollected.toLocaleString()}`} />
               <ReportRow label="Current Arrears" value={`KES ${Math.max(0, totalExpected - totalCollected).toLocaleString()}`} highlight />
             </div>
          </ReportSection>
          <ReportSection title="Property P&L" icon={<TrendingUp className="text-blue-500"/>}>
             <div className="space-y-4">
               <ReportRow label="Gross Operating Income" value={`KES ${totalCollected.toLocaleString()}`} />
               <ReportRow label="Maintenance Expenses" value={`KES ${totalMaintenance.toLocaleString()}`} />
               <ReportRow label="Net Operating Income" value={`KES ${(totalCollected - totalMaintenance).toLocaleString()}`} bold />
             </div>
          </ReportSection>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {selectedTenant && <TenantIntelligenceModal tenant={selectedTenant} payments={payments.filter(p => p.tenantId === selectedTenant.id)} onClose={() => setSelectedTenant(null)} />}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Expected Revenue" value={`KES ${totalExpected.toLocaleString()}`} icon={<DollarSign className="text-blue-500" />} change="+12%" />
        <StatCard title="Total Collected" value={`KES ${totalCollected.toLocaleString()}`} icon={<TrendingUp className="text-emerald-500" />} change="+5%" />
        <StatCard title="Occupancy" value={`${occupancyRate.toFixed(1)}%`} icon={<Home className="text-amber-500" />} change="Stable" />
        <StatCard title="Collection Rate" value={`${((totalCollected/totalExpected)*100).toFixed(0)}%`} icon={<Users className="text-purple-500" />} change="On Target" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm">
          <h3 className="text-lg font-bold mb-6">Financial Snapshot</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={financialData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#94a3b8'}} />
                <YAxis hide />
                <Tooltip />
                <Bar dataKey="amount" radius={[8, 8, 0, 0]}>
                  {financialData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index]} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col">
          <h3 className="text-lg font-bold mb-6">Occupancy Mix</h3>
          <div className="h-[250px] w-full flex items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={occupancyData} cx="50%" cy="50%" innerRadius={70} outerRadius={90} paddingAngle={5} dataKey="value">
                  {occupancyData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="grid grid-cols-3 gap-4 mt-4">
            {occupancyData.map((item, idx) => (
              <div key={item.name} className="text-center">
                <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{item.name}</div>
                <div className="text-xl font-bold" style={{ color: COLORS[idx] }}>{item.value}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="flex justify-between items-center mb-6">
           <h3 className="text-lg font-bold">Portfolio Tenant Audit</h3>
           <button className="text-amber-500 text-xs font-black uppercase tracking-widest flex items-center gap-1"><Download size={14}/> Export CSV</button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="border-b bg-slate-50">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500">Tenant</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500">Unit</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500">Status</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500">Owed</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 text-right">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {tenants.map(t => (
                <tr key={t.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-800">{t.name}</div>
                    <div className="text-[10px] text-slate-400 font-mono">{t.idNumber}</div>
                  </td>
                  <td className="px-6 py-4 font-medium">{t.houseNumber}</td>
                  <td className="px-6 py-4"><BillStatusBadge status={t.bills.status} /></td>
                  <td className="px-6 py-4 font-bold text-slate-700">KES {t.bills.total.toLocaleString()}</td>
                  <td className="px-6 py-4 text-right">
                    <button onClick={() => setSelectedTenant(t)} className="p-2 bg-slate-100 hover:bg-amber-500 hover:text-white text-slate-500 rounded-xl transition-all"><Eye size={16} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

// ... TenantIntelligenceModal and helper components same as previously implemented ...
const TenantIntelligenceModal: React.FC<{ tenant: Tenant, payments: PaymentRecord[], onClose: () => void }> = ({ tenant, payments, onClose }) => {
