  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);

  const totalPaid = payments.reduce((acc, p) => acc + p.amount, 0);

  const handleRunAnalysis = async () => {
    setLoadingAI(true);
    try {
      const insight = await analyzeTenantFinancials(tenant.name, tenant.bills, payments);
      setAiInsight(insight);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingAI(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-fadeIn">
      <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-slideUp">
        <div className="bg-slate-900 p-8 text-white relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 opacity-5"><User size={140} /></div>
          <div className="flex justify-between items-start relative z-10">
            <div>
              <span className="bg-amber-500 text-white text-[10px] font-black uppercase px-2 py-1 rounded">Resident Profile</span>
              <h2 className="text-4xl font-royal text-amber-400 mt-2">{tenant.name}</h2>
              <p className="text-slate-400">Unit {tenant.houseNumber} • Joined {tenant.joinDate}</p>
            </div>
            <button onClick={onClose} className="p-2 bg-white/10 rounded-full hover:bg-white/20"><X size={24}/></button>
          </div>
          <div className="flex gap-4 mt-8">
            <ModalTab active={activeTab === 'overview'} onClick={() => setActiveTab('overview')} label="Finances" />
            <ModalTab active={activeTab === 'ledger'} onClick={() => setActiveTab('ledger')} label="Payments" />
            <ModalTab active={activeTab === 'analysis'} onClick={() => setActiveTab('analysis')} label="AI Intel" />
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-10 bg-slate-50">
          {activeTab === 'overview' && (
            <div className="space-y-6">
              <div className="grid grid-cols-3 gap-6">
                <MetricBox label="Collected" value={`KES ${totalPaid.toLocaleString()}`} color="emerald" />
                <MetricBox label="Outstanding" value={`KES ${tenant.bills.total.toLocaleString()}`} color="rose" />
