                  <thead className="bg-slate-50"><tr><th className="p-4 font-bold text-slate-500">Date</th><th className="p-4 font-bold text-slate-500">Ref</th><th className="p-4 font-bold text-slate-500">Type</th><th className="p-4 text-right font-bold text-slate-500">Amount</th></tr></thead>
                  <tbody className="divide-y">
                    {payments.map(p => (
                      <tr key={p.id} className="hover:bg-slate-50 transition-colors">
