                      </tr>
                    ))}
                    {payments.length === 0 && <tr><td colSpan={4} className="p-10 text-center text-slate-400 italic">No historical data.</td></tr>}
                  </tbody>
               </table>
            </div>
          )}
          {activeTab === 'analysis' && (
            <div className="bg-slate-900 p-10 rounded-[2.5rem] text-center space-y-6">
              <Activity className="text-amber-400 mx-auto" size={48} />
              <div className="max-w-md mx-auto">
                <h4 className="text-white text-lg font-royal mb-2">Behavioral Analysis</h4>
