const ReportSection: React.FC<{ title: string, icon: React.ReactNode, children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
    <div className="flex items-center gap-3 mb-8">
      <div className="p-3 bg-slate-50 rounded-xl">{icon}</div>
      <h3 className="text-lg font-bold text-slate-800">{title}</h3>
    </div>
    {children}
  </div>
);

const ReportRow: React.FC<{ label: string, value: string, bold?: boolean, highlight?: boolean }> = ({ label, value, bold, highlight }) => (
  <div className={`flex justify-between items-center py-3 border-b border-slate-50 last:border-0 ${bold ? 'font-bold text-slate-900' : 'text-slate-600'}`}>
    <span className="text-sm">{label}</span>
    <span className={`font-royal ${highlight ? 'text-rose-600' : ''}`}>{value}</span>
  </div>
);

const MetricBox: React.FC<{ label: string, value: string, color: 'emerald' | 'rose' | 'slate' }> = ({ label, value, color }) => {
  const colors = {
    emerald: 'text-emerald-600 bg-emerald-50',
    rose: 'text-rose-600 bg-rose-50',
    slate: 'text-slate-600 bg-slate-50'
  };
  return (
    <div className={`p-6 rounded-2xl ${colors[color]} border border-white/20`}>
      <div className="text-[10px] uppercase font-black tracking-widest mb-1 opacity-70">{label}</div>
      <div className="text-2xl font-bold font-royal truncate">{value}</div>
    </div>
  );
};

const ModalTab: React.FC<{ active: boolean, onClick: () => void, label: string }> = ({ active, onClick, label }) => (
  <button onClick={onClick} className={`px-4 py-2 rounded-lg text-xs font-bold uppercase transition-all ${active ? 'bg-amber-500 text-white shadow-lg' : 'bg-white/10 text-slate-400 hover:text-white'}`}>{label}</button>
);

const BillStatusBadge: React.FC<{ status: 'PAID' | 'UNPAID' | 'PARTIAL' }> = ({ status }) => {
  const configs = {
    PAID: { color: 'bg-emerald-100 text-emerald-700 border-emerald-200', icon: <CheckCircle2 size={12} />, label: 'PAID' },
    PARTIAL: { color: 'bg-amber-100 text-amber-700 border-amber-200', icon: <Clock size={12} />, label: 'PARTIAL' },
    UNPAID: { color: 'bg-rose-100 text-rose-700 border-rose-200', icon: <AlertTriangle size={12} />, label: 'UNPAID' }
  };
  const config = configs[status];
  return (
    <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-[10px] font-black border ${config.color}`}>
      {config.icon} {config.label}
    </span>
  );
};

const StatCard: React.FC<{ title: string, value: string, icon: React.ReactNode, change: string }> = ({ title, value, icon, change }) => (
  <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm transition-transform hover:-translate-y-1">
