  view: string;
}

export const LandlordDashboard: React.FC<Props> = ({ tenants, houses, payments, expenses, view }) => {
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [aiReport, setAiReport] = useState<string | null>(null);
  const [loadingAI, setLoadingAI] = useState(false);

  const totalExpected = tenants.reduce((acc, t) => acc + t.bills.rent, 0);
  const totalCollected = payments.reduce((acc, p) => acc + p.amount, 0);
  const totalMaintenance = houses.reduce((acc, h) => acc + h.repairs.reduce((rAcc, r) => rAcc + r.cost, 0), 0);
  const occupancyRate = (houses.length > 0) ? (houses.filter(h => h.status === HouseStatus.RENTED).length / houses.length) * 100 : 0;
  const arrears = Math.max(0, totalExpected - totalCollected);

  const handleGenerateAIReport = async () => {
    setLoadingAI(true);
    try {
      const report = await analyzePropertyHealth(houses, expenses);
      setAiReport(report);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingAI(false);
    }
  };

  const COLORS = ['#1F6AE1', '#22C55E', '#F59E0B', '#EF4444']; // Blue, Green, Amber, Red

  const occupancyData = [
    { name: 'Occupied', value: houses.filter(h => h.status === HouseStatus.RENTED).length },
    { name: 'Vacant', value: houses.filter(h => h.status === HouseStatus.VACANT).length },
    { name: 'Repair', value: houses.filter(h => h.status === HouseStatus.UNDER_REPAIR).length },
  ];

  const financialData = [
    { name: 'Expected', amount: totalExpected },
    { name: 'Collected', amount: totalCollected },
    { name: 'Expenses', amount: totalMaintenance },
  ];

  if (view === 'reports') {
    return (
      <div className="space-y-8 animate-fadeIn">
        <div className="flex justify-between items-center">
          <div>
             <h2 className="text-3xl font-royal text-neutral-900 font-bold">Portfolio Audit</h2>
             <p className="text-neutral-400 text-sm">Detailed financial performance and forecasting</p>
          </div>
          <button onClick={handleGenerateAIReport} disabled={loadingAI} className="flex items-center gap-2 bg-royal-500 text-white px-6 py-3 rounded-2xl font-bold hover:bg-royal-600 transition-all shadow-xl shadow-royal-500/20 active:scale-95">
            {loadingAI ? <Activity className="animate-spin" size={18}/> : <Briefcase size={18}/>}
            {loadingAI ? 'Scanning Portfolio...' : 'Generate Executive Report'}
          </button>
        </div>

        {aiReport && (
          <div className="bg-white border border-royal-100 p-8 rounded-[2.5rem] relative overflow-hidden shadow-sm">
            <div className="absolute top-0 right-0 p-8 opacity-5 text-royal-500"><FileText size={160}/></div>
            <div className="flex items-center gap-3 mb-6">
              <span className="bg-royal-100 text-royal-700 text-[10px] font-black uppercase tracking-widest px-2.5 py-1.5 rounded-lg border border-royal-200">AI Intelligence Insight</span>
            </div>
            <p className="text-xl font-royal text-neutral-800 italic leading-relaxed z-10 relative">"{aiReport}"</p>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <ReportSection title="Rent Roll Breakdown" icon={<Wallet className="text-royal-500"/>}>
             <div className="space-y-6">
               <ReportRow label="Projected Gross Revenue" value={`KES ${totalExpected.toLocaleString()}`} />
               <ReportRow label="Actual Net Collection" value={`KES ${totalCollected.toLocaleString()}`} />
               <ReportRow label="Outstanding Arrears" value={`KES ${arrears.toLocaleString()}`} highlight />
               <div className="pt-4 border-t border-neutral-50 flex justify-between items-center">
                  <span className="text-xs font-black text-neutral-400 uppercase tracking-widest">Efficiency</span>
                  <span className="text-xl font-bold text-royal-500">{((totalCollected/totalExpected)*100).toFixed(1)}%</span>
               </div>
             </div>
          </ReportSection>
          <ReportSection title="Profit & Loss Matrix" icon={<TrendingUp className="text-green-500"/>}>
             <div className="space-y-6">
               <ReportRow label="Operating Income" value={`KES ${totalCollected.toLocaleString()}`} />
               <ReportRow label="Maintenance Outlay" value={`KES ${totalMaintenance.toLocaleString()}`} />
               <ReportRow label="Management Fees (10%)" value={`KES ${(totalCollected * 0.1).toLocaleString()}`} />
               <div className="pt-4 border-t border-neutral-50 flex justify-between items-center">
                  <span className="text-xs font-black text-neutral-400 uppercase tracking-widest">Net Profit</span>
                  <span className="text-xl font-bold text-green-600 font-royal">KES ${(totalCollected - totalMaintenance - (totalCollected * 0.1)).toLocaleString()}</span>
               </div>
             </div>
          </ReportSection>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fadeIn">
      {selectedTenant && <TenantIntelligenceModal tenant={selectedTenant} payments={payments.filter(p => p.tenantId === selectedTenant.id)} onClose={() => setSelectedTenant(null)} />}

      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-royal text-neutral-900 font-bold">Ownership Dashboard</h2>
          <p className="text-neutral-400 text-sm">Real-time portfolio visibility</p>
        </div>
        <div className="flex gap-2 bg-neutral-100 p-1.5 rounded-2xl border border-neutral-200 shadow-sm">
           <button className="px-4 py-2 bg-white rounded-xl text-xs font-bold text-neutral-800 shadow-sm">Monthly</button>
           <button className="px-4 py-2 text-xs font-bold text-neutral-500">Yearly</button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Portfolio Income" value={`KES ${totalCollected.toLocaleString()}`} icon={<Wallet className="text-royal-500" />} trend="up" change="+4.2%" />
        <StatCard title="Active Arrears" value={`KES ${arrears.toLocaleString()}`} icon={<AlertTriangle className="text-red-500" />} trend="down" change="-12%" />
        <StatCard title="Unit Occupancy" value={`${occupancyRate.toFixed(1)}%`} icon={<Home className="text-green-500" />} trend="up" change="+2.1%" />
        <StatCard title="Collection Cycle" value="On Track" icon={<Clock className="text-amber-500" />} change="Day 15" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-10 rounded-[2.5rem] border border-neutral-200 shadow-sm transition-all hover:shadow-xl hover:shadow-neutral-200/40">
          <div className="flex justify-between items-center mb-10">
            <h3 className="text-lg font-bold text-neutral-800">Financial Growth Volume</h3>
            <button className="p-2 text-neutral-400 hover:bg-neutral-50 rounded-xl transition-all"><MoreHorizontal size={20}/></button>
          </div>
          <div className="h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={financialData} barSize={60}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#F1F5F9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 11, fill: '#94A3B8', fontWeight: 600}} />
                <YAxis hide />
                <Tooltip cursor={{fill: '#F8FAFC'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }} />
                <Bar dataKey="amount" radius={[12, 12, 0, 0]}>
                  {financialData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-neutral-900 p-10 rounded-[2.5rem] text-white flex flex-col justify-between shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-0 group-hover:opacity-10 transition-opacity duration-700 text-royal-500"><TrendingUp size={160} /></div>
          <div>
            <h3 className="text-lg font-bold mb-8">Occupancy Analysis</h3>
            <div className="h-[220px] w-full flex items-center justify-center">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={occupancyData} cx="50%" cy="50%" innerRadius={70} outerRadius={90} paddingAngle={8} dataKey="value">
                    {occupancyData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="rgba(0,0,0,0)" />)}
                  </Pie>
                  <Tooltip />
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div className="space-y-4 mt-8">
              {occupancyData.map((item, idx) => (
                <div key={item.name} className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[idx] }} />
                    <span className="text-xs text-neutral-400 font-medium">{item.name}</span>
                  </div>
                  <span className="text-sm font-bold">{item.value} Units</span>
                </div>
              ))}
            </div>
          </div>
          <div className="pt-10 border-t border-neutral-800">
             <button className="w-full flex items-center justify-center gap-2 text-xs font-black uppercase tracking-widest text-royal-300 hover:text-royal-500 transition-all">Download Audit Report <ArrowUpRight size={14}/></button>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-neutral-200 shadow-sm overflow-hidden">
        <div className="p-10 border-b border-neutral-100 flex justify-between items-center">
           <div>
             <h3 className="text-lg font-bold text-neutral-800">Tenant Financial Audit</h3>
             <p className="text-xs text-neutral-400 font-medium">Monthly collection status per unit</p>
           </div>
           <div className="flex gap-4">
              <div className="relative">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400" />
                <input type="text" placeholder="Filter residents..." className="pl-9 pr-4 py-2.5 bg-neutral-50 border border-neutral-200 rounded-xl text-xs outline-none focus:border-royal-500 transition-all" />
              </div>
              <button className="flex items-center gap-2 text-xs font-black uppercase tracking-widest text-neutral-500 hover:text-royal-500 transition-all"><Download size={14}/> CSV</button>
           </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-neutral-50/50">
              <tr>
                <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Resident Details</th>
                <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Property Unit</th>
                <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Collection Status</th>
                <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Total Owed</th>
                <th className="px-10 py-6 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Insight</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-neutral-100">
              {tenants.map(t => (
                <tr key={t.id} className="hover:bg-neutral-50/80 transition-all group">
                  <td className="px-10 py-6">
                    <div className="font-bold text-neutral-800 group-hover:text-royal-500 transition-colors">{t.name}</div>
                    <div className="text-[10px] text-neutral-400 font-mono tracking-tighter">{t.phoneNumber}</div>
                  </td>
                  <td className="px-10 py-6">
                    <span className="font-semibold text-neutral-600 bg-neutral-100 px-3 py-1 rounded-lg border border-neutral-200 text-xs">{t.houseNumber}</span>
                  </td>
                  <td className="px-10 py-6"><BillStatusBadge status={t.bills.status} /></td>
                  <td className="px-10 py-6 font-bold text-neutral-700">KES {t.bills.total.toLocaleString()}</td>
                  <td className="px-10 py-6 text-right">
                    <button onClick={() => setSelectedTenant(t)} className="p-3 bg-neutral-100 hover:bg-royal-500 hover:text-white text-neutral-500 rounded-2xl transition-all hover:shadow-lg hover:shadow-royal-500/20"><Eye size={18} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

// Simplified but beautiful sub-components
