  <div className="bg-white p-8 rounded-[2rem] border border-neutral-200 shadow-sm transition-all hover:-translate-y-1 group">
    <div className="flex items-center justify-between mb-6">
      <div className="p-3.5 bg-neutral-50 rounded-2xl group-hover:bg-royal-50 transition-colors">{icon}</div>
      <div className={`flex items-center gap-1 text-[10px] font-black px-2.5 py-1.5 rounded-lg border ${trend === 'up' ? 'bg-green-50 text-green-700 border-green-100' : trend === 'down' ? 'bg-red-50 text-red-700 border-red-100' : 'bg-neutral-50 text-neutral-600 border-neutral-200'}`}>
         {trend === 'up' ? <TrendingUp size={12}/> : trend === 'down' ? <TrendingDown size={12}/> : null}
