const BillStatusBadge: React.FC<{ status: 'PAID' | 'UNPAID' | 'PARTIAL' }> = ({ status }) => {
  const configs = {
    PAID: { color: 'bg-green-100 text-green-700 border-green-200', icon: <CheckCircle2 size={12} />, label: 'FULLY PAID' },
    PARTIAL: { color: 'bg-amber-100 text-amber-700 border-amber-200', icon: <Clock size={12} />, label: 'PENDING PARTIAL' },
    UNPAID: { color: 'bg-red-100 text-red-700 border-red-200', icon: <AlertTriangle size={12} />, label: 'OVERDUE ARREARS' }
  };
  const config = configs[status];
  return (
    <span className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-xl text-[10px] font-black border ${config.color} tracking-tight`}>
      {config.icon} {config.label}
    </span>
  );
};

const ModalTab: React.FC<{ active: boolean, onClick: () => void, label: string }> = ({ active, onClick, label }) => (
