    green: 'text-green-600 bg-green-50 border-green-100',
    red: 'text-red-600 bg-red-50 border-red-100',
    blue: 'text-royal-500 bg-royal-50 border-royal-100'
  };
  return (
    <div className={`p-8 rounded-[2rem] ${styles[color]} border shadow-sm group hover:-translate-y-1 transition-all`}>
