import React, { useState, useMemo, useEffect } from 'react';
import { Tenant, House, HouseStatus, Bill, Repair, PastTenant, PaymentRecord } from '../types';
import { 
  UserPlus, Droplets, Send, Wrench, RefreshCw, ChevronRight, X, User, Phone, Mail, 
  Hash, Home, CheckCircle2, CircleDashed, Hammer, Users, AlertTriangle, Clock, 
  History, DollarSign, Activity, Eye, Search, TrendingUp, TrendingDown, Receipt, 
  BarChart3, ShieldAlert, ArrowRight, MapPin
} from 'lucide-react';
import { ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid, Cell } from 'recharts';
import { generateTenantNotification, analyzeTenantFinancials } from '../services/geminiService';

interface Props {
  tenants: Tenant[];
  houses: House[];
  payments: PaymentRecord[];
  onAddTenant: (t: Tenant) => void;
  onUpdateBills: (id: string, water: number) => void;
  onUpdateHouse: (id: string, status: HouseStatus) => void;
  activeTab?: string;
}

export const CaretakerDashboard: React.FC<Props> = ({ 
  tenants, houses, payments, onAddTenant, onUpdateBills, onUpdateHouse,
  activeTab: propTab 
}) => {
  const [activeTab, setActiveTab] = useState<'houses' | 'tenants' | 'billing'>('houses');
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedHouse, setSelectedHouse] = useState<House | null>(null);
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [loadingAI, setLoadingAI] = useState<string | null>(null);

  useEffect(() => {
    if (propTab) {
      if (propTab === 'houses' || propTab === 'properties') setActiveTab('houses');
      else if (propTab === 'tenants') setActiveTab('tenants');
      else if (propTab === 'billing' || propTab === 'payments') setActiveTab('billing');
    }
  }, [propTab]);

  const [newTenant, setNewTenant] = useState({
    name: '',
    email: '',
    houseNumber: '',
    idNumber: '',
    phoneNumber: '',
    nextOfKin: '',
    rent: 0
  });

  const handleSendReminder = async (tenant: Tenant) => {
    setLoadingAI(tenant.id);
    try {
      const message = await generateTenantNotification(tenant.name, tenant.bills.total);
      alert(`AI Draft Notification for ${tenant.name}:\n\n"${message}"\n\nNotification sent to ${tenant.phoneNumber}`);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingAI(null);
    }
  };

  const handleRegisterTenant = (e: React.FormEvent) => {
    e.preventDefault();
    const tenant: Tenant = {
      id: `t-${Date.now()}`,
      name: newTenant.name,
      email: newTenant.email,
      houseNumber: newTenant.houseNumber,
      idNumber: newTenant.idNumber,
      phoneNumber: newTenant.phoneNumber,
      nextOfKin: newTenant.nextOfKin,
      joinDate: new Date().toISOString().split('T')[0],
      bills: {
        rent: newTenant.rent,
        water: 0,
        garbage: 500,
        total: newTenant.rent + 500,
        status: 'UNPAID'
      }
    };
    onAddTenant(tenant);
    setShowAddModal(false);
    setNewTenant({ name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0 });
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {showAddModal && <AddTenantModal houses={houses} newTenant={newTenant} setNewTenant={setNewTenant} onClose={() => setShowAddModal(false)} onSubmit={handleRegisterTenant} />}
      {selectedHouse && <HouseDetailModal house={selectedHouse} onClose={() => setSelectedHouse(null)} currentTenant={tenants.find(t => t.houseNumber === selectedHouse.houseNumber)} />}
      {selectedTenant && <TenantIntelligenceModal tenant={selectedTenant} payments={payments.filter(p => p.tenantId === selectedTenant.id)} onClose={() => setSelectedTenant(null)} />}

      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-royal text-neutral-900 font-bold">Property Operations</h2>
          <p className="text-neutral-400 text-sm mt-1">Daily unit management and utility tracking</p>
        </div>
        <div className="flex bg-neutral-100 p-1.5 rounded-2xl border border-neutral-200 shadow-sm">
          {(['houses', 'tenants', 'billing'] as const).map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-white text-royal-500 shadow-sm' : 'text-neutral-400 hover:text-neutral-600'}`}>
              {tab}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'houses' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {houses.map(house => (
            <UnitCard key={house.id} house={house} onUpdate={onUpdateHouse} onView={() => setSelectedHouse(house)} />
          ))}
          <button onClick={() => setShowAddModal(true)} className="border-2 border-dashed border-neutral-200 rounded-[2.5rem] flex flex-col items-center justify-center p-12 text-neutral-400 hover:border-royal-400 hover:text-royal-500 hover:bg-royal-50 transition-all group min-h-[300px] shadow-sm">
            <div className="bg-neutral-50 group-hover:bg-royal-100 p-6 rounded-3xl mb-4 transition-colors"><UserPlus size={40} /></div>
            <span className="font-black text-xs uppercase tracking-widest">Register New Resident</span>
          </button>
        </div>
      )}

      {activeTab === 'tenants' && (
        <div className="bg-white rounded-[2.5rem] border border-neutral-200 shadow-sm overflow-hidden animate-slideUp">
          <div className="p-8 border-b border-neutral-100 flex justify-between items-center">
             <h3 className="font-bold text-lg">Active Resident List</h3>
             <div className="flex gap-4">
                <div className="relative">
                  <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400" />
                  <input type="text" placeholder="Search by name..." className="pl-9 pr-4 py-2 bg-neutral-50 border border-neutral-200 rounded-xl text-xs outline-none focus:border-royal-500" />
                </div>
             </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-neutral-50/50">
                <tr>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Tenant Name</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Unit No</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Payment Status</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-neutral-50">
                {tenants.map(t => (
                  <tr key={t.id} className="hover:bg-neutral-50/50 transition-all group">
                    <td className="px-8 py-6">
                      <div className="font-bold text-neutral-800">{t.name}</div>
                      <div className="text-[10px] text-neutral-400 font-medium tracking-tight flex items-center gap-1"><Phone size={10}/> {t.phoneNumber}</div>
                    </td>
                    <td className="px-8 py-6">
                      <span className="font-bold text-royal-500 bg-royal-50 px-3 py-1 rounded-lg border border-royal-100 text-xs">{t.houseNumber}</span>
                    </td>
                    <td className="px-8 py-6"><BillStatusBadge status={t.bills.status} /></td>
                    <td className="px-8 py-6 text-right">
                      <div className="flex justify-end gap-3">
                        <button onClick={() => setSelectedTenant(t)} className="p-2.5 bg-neutral-100 hover:bg-neutral-200 text-neutral-500 rounded-xl transition-all"><Eye size={16} /></button>
                        <button onClick={() => handleSendReminder(t)} disabled={loadingAI === t.id} className="inline-flex items-center gap-2 bg-royal-500 hover:bg-royal-600 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-royal-500/20 disabled:opacity-50 transition-all active:scale-95">
                          {loadingAI === t.id ? <Activity className="animate-spin" size={14}/> : <Send size={14}/>}
                          Notify
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'billing' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm animate-slideUp">
            <h3 className="text-xl font-bold mb-8 flex items-center gap-3"><Droplets className="text-cyan-500" /> Utility Monitoring</h3>
            <div className="space-y-4">
              {tenants.map(t => (
                <div key={t.id} className="flex items-center justify-between p-6 bg-neutral-50 rounded-[2rem] border border-neutral-100 group hover:border-royal-200 transition-all">
                  <div>
                    <div className="font-black text-neutral-400 text-[10px] uppercase tracking-widest mb-1">Unit {t.houseNumber}</div>
                    <div className="font-bold text-neutral-800 text-lg">{t.name}</div>
                    <div className="text-xs text-neutral-400 mt-1">Outstanding: KES {t.bills.total.toLocaleString()}</div>
                  </div>
                  <div className="flex flex-col items-end gap-2">
                     <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">Water Units</label>
                     <input type="number" placeholder="0.00" className="w-28 p-3 text-sm font-bold border-2 border-neutral-200 rounded-xl focus:border-royal-500 outline-none text-right transition-all" onBlur={(e) => onUpdateBills(t.id, Number(e.target.value))} />
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="bg-neutral-900 text-white p-10 rounded-[3rem] shadow-2xl relative overflow-hidden flex flex-col justify-between group">
            <div className="absolute top-0 right-0 p-10 opacity-0 group-hover:opacity-10 transition-opacity duration-700 text-royal-500"><Wrench size={160} /></div>
            <div>
              <h3 className="text-xl font-bold mb-8 flex items-center gap-3 font-royal text-royal-100"><RefreshCw className="text-royal-500" /> Maintenance Records</h3>
              <div className="space-y-4 max-h-[500px] overflow-y-auto scrollbar-hide">
                <MaintenanceItem date="Today" task="Gate Lock Mechanism" cost={4500} house="External" />
                <MaintenanceItem date="Yesterday" task="Plumbing Leakage B4" cost={8200} house="B4" />
                <MaintenanceItem date="12th Sep" task="Security Light Replace" cost={1500} house="Common" />
              </div>
            </div>
            <button className="w-full mt-10 bg-royal-500 text-white py-5 rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-royal-600 shadow-xl shadow-royal-500/20 active:scale-95 transition-all">Log Property Expense</button>
          </div>
        </div>
      )}
    </div>
  );
};

const UnitCard: React.FC<{ house: House, onUpdate: any, onView: any }> = ({ house, onUpdate, onView }) => {
  const isRented = house.status === HouseStatus.RENTED;
  const isVacant = house.status === HouseStatus.VACANT;

  const statusColor = isRented ? 'emerald' : isVacant ? 'amber' : 'red';
  const borderClass = isRented ? 'border-green-100 hover:border-green-300' : isVacant ? 'border-amber-100 hover:border-amber-300' : 'border-red-100 hover:border-red-300';
  const accentClass = isRented ? 'bg-green-500' : isVacant ? 'bg-amber-500' : 'bg-red-500';

  return (
    <div className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all group relative overflow-hidden flex flex-col shadow-sm hover:shadow-xl hover:shadow-neutral-200/50 ${borderClass}`}>
      <div className={`absolute top-0 left-0 right-0 h-1.5 ${accentClass}`} />
      <div className="flex justify-between items-start mb-10">
        <div>
          <h3 className="text-3xl font-royal font-black text-neutral-800 tracking-tighter">{house.houseNumber}</h3>
          <p className="text-[10px] text-neutral-400 font-black uppercase tracking-widest mt-1.5">{house.type} Suite</p>
        </div>
        <div className="flex flex-col items-end gap-2">
          <StatusBadge status={house.status} />
          <button onClick={onView} className="p-2.5 bg-neutral-50 hover:bg-neutral-200 text-neutral-500 rounded-xl transition-all border border-neutral-100"><Eye size={16} /></button>
        </div>
      </div>

      <div className="space-y-4 mb-10 flex-1">
        <div className="flex justify-between text-xs items-center"><span className="text-neutral-400 font-bold uppercase tracking-tight">Revenue</span><span className="font-black text-neutral-800">KES {house.totalEarnings.toLocaleString()}</span></div>
        <div className="flex justify-between text-xs items-center"><span className="text-neutral-400 font-bold uppercase tracking-tight">Incidents</span><span className="font-black text-amber-600 underline underline-offset-4">{house.repairs.length} History</span></div>
        <div className="flex justify-between text-xs items-center"><span className="text-neutral-400 font-bold uppercase tracking-tight">Cycle</span><span className="font-bold text-neutral-600">{house.lastVacantDate}</span></div>
      </div>

      <div className="grid grid-cols-3 gap-1.5 bg-neutral-100/80 p-1.5 rounded-2xl border border-neutral-200 shadow-inner">
        <UnitStatusBtn active={house.status === HouseStatus.RENTED} onClick={() => onUpdate(house.id, HouseStatus.RENTED)} color="green" label="Rented" icon={<CheckCircle2 size={12}/>} />
        <UnitStatusBtn active={house.status === HouseStatus.VACANT} onClick={() => onUpdate(house.id, HouseStatus.VACANT)} color="amber" label="Vacant" icon={<CircleDashed size={12}/>} />
        <UnitStatusBtn active={house.status === HouseStatus.UNDER_REPAIR} onClick={() => onUpdate(house.id, HouseStatus.UNDER_REPAIR)} color="red" label="Repair" icon={<Hammer size={12}/>} />
      </div>
    </div>
  );
};

const UnitStatusBtn: React.FC<{ active: boolean, onClick: () => void, color: 'green' | 'amber' | 'red', label: string, icon: React.ReactNode }> = ({ active, onClick, color, label, icon }) => {
  const variants = {
    green: active ? 'bg-green-500 text-white shadow-lg shadow-green-500/20' : 'text-neutral-400 hover:text-green-600 hover:bg-green-50',
    amber: active ? 'bg-amber-500 text-white shadow-lg shadow-amber-500/20' : 'text-neutral-400 hover:text-amber-600 hover:bg-amber-50',
    red: active ? 'bg-red-500 text-white shadow-lg shadow-red-500/20' : 'text-neutral-400 hover:text-red-600 hover:bg-red-50',
  };
  return <button onClick={onClick} className={`flex flex-col items-center justify-center py-3 rounded-xl transition-all gap-1 ${variants[color]}`}>{icon}<span className="text-[8px] font-black uppercase tracking-tight">{label}</span></button>;
};

