          <button type="submit" className="flex-[2] py-5 rounded-2xl font-black text-xs uppercase tracking-widest text-white bg-royal-500 hover:bg-royal-600 shadow-2xl shadow-royal-500/30 transition-all active:scale-95 flex items-center justify-center gap-2">Finalize Registration <ArrowRight size={16}/></button>
