);

export default App;

import React, { useState } from 'react';
import { Tenant, House, PaymentRecord, Expense, HouseStatus } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid } from 'recharts';
import { 
  TrendingUp, Users, DollarSign, Home, Clock, CheckCircle2, 
  AlertTriangle, Activity, X, User, Eye, FileText, 
  Download, Briefcase, Wallet, Plus, Trash2, Filter
} from 'lucide-react';
import { analyzeTenantFinancials, analyzePropertyHealth } from '../services/geminiService';

interface Props {
  tenants: Tenant[];
  houses: House[];
  payments: PaymentRecord[];
  expenses: Expense[];
  view: string;
  onAddExpense: (expense: Expense) => void;
}

export const LandlordDashboard: React.FC<Props> = ({ tenants, houses, payments, expenses, view, onAddExpense }) => {
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [showExpenseModal, setShowExpenseModal] = useState(false);
  const [loadingAI, setLoadingAI] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Stats calculations
  const totalExpected = tenants.reduce((acc, t) => acc + t.bills.rent, 0);
  const totalCollected = payments.reduce((acc, p) => acc + p.amount, 0);
  const totalExpenses = expenses.reduce((acc, e) => acc + e.amount, 0);
  const maintenanceExpenses = houses.reduce((acc, h) => acc + h.repairs.reduce((rAcc, r) => rAcc + r.cost, 0), 0);
  const occupancyRate = houses.length > 0 ? (houses.filter(h => h.status === HouseStatus.RENTED).length / houses.length) * 100 : 0;
  const netIncome = totalCollected - totalExpenses - maintenanceExpenses;

  const COLORS = ['#1F6AE1', '#22C55E', '#F59E0B', '#EF4444'];

  const occupancyData = [
    { name: 'Occupied', value: houses.filter(h => h.status === HouseStatus.RENTED).length },
    { name: 'Vacant', value: houses.filter(h => h.status === HouseStatus.VACANT).length },
    { name: 'Repair', value: houses.filter(h => h.status === HouseStatus.UNDER_REPAIR).length },
  ];

  const financialData = [
    { name: 'Gross Income', amount: totalCollected },
    { name: 'Maintenance', amount: maintenanceExpenses },
    { name: 'Operating Exp', amount: totalExpenses },
    { name: 'Net Income', amount: netIncome },
  ];

  const handleAIReport = async () => {
    setLoadingAI(true);
    try {
      const result = await analyzePropertyHealth(houses, [...expenses, ...houses.flatMap(h => h.repairs)]);
      setAiReport(result);
    } catch (e) { console.error(e); }
    finally { setLoadingAI(false); }
  };

  if (view === 'expenses') {
    return (
      <div className="space-y-8 animate-fadeIn">
        <div className="flex justify-between items-center">
          <div>
            <h2 className="text-3xl font-royal font-bold text-neutral-900">Expense Ledger</h2>
            <p className="text-neutral-400 text-sm">Monitor operational costs and maintenance outlay</p>
          </div>
          <button onClick={() => setShowExpenseModal(true)} className="flex items-center gap-2 bg-royal-500 text-white px-6 py-3 rounded-2xl font-bold hover:bg-royal-600 shadow-xl shadow-royal-500/20">
            <Plus size={20}/> Log New Expense
          </button>
        </div>

        {showExpenseModal && <AddExpenseModal onAdd={onAddExpense} onClose={() => setShowExpenseModal(false)} />}

        <div className="bg-white rounded-[2.5rem] border border-neutral-200 shadow-sm overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-neutral-50 border-b">
              <tr>
                <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Date</th>
                <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Category</th>
                <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Description</th>
                <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Amount</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-neutral-50">
              {expenses.length === 0 && (
                <tr><td colSpan={4} className="p-20 text-center text-neutral-300 italic">No operational expenses logged yet.</td></tr>
              )}
              {expenses.map(e => (
                <tr key={e.id} className="hover:bg-neutral-50 transition-colors">
                  <td className="px-8 py-6 text-sm text-neutral-600 font-medium">{new Date(e.date).toLocaleDateString()}</td>
                  <td className="px-8 py-6">
                    <span className="bg-neutral-100 text-neutral-600 px-3 py-1 rounded-lg text-[10px] font-black uppercase border border-neutral-200">{e.category}</span>
                  </td>
                  <td className="px-8 py-6 text-sm font-bold text-neutral-800">{e.description}</td>
                  <td className="px-8 py-6 text-right font-black text-red-500">KES {e.amount.toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  if (view === 'reports') {
    return (
      <div className="space-y-8 animate-fadeIn">
        <div className="flex justify-between items-center">
          <div>
            <h2 className="text-3xl font-royal font-bold text-neutral-900">Portfolio Performance</h2>
            <p className="text-neutral-400 text-sm">Automated intelligence and financial summaries</p>
          </div>
          <button onClick={handleAIReport} disabled={loadingAI} className="flex items-center gap-2 bg-royal-900 text-white px-6 py-3 rounded-2xl font-bold hover:bg-neutral-800 shadow-xl active:scale-95 transition-all">
            {loadingAI ? <Activity className="animate-spin" size={18}/> : <Briefcase size={18}/>}
            {loadingAI ? 'Analyzing...' : 'Generate AI Executive Audit'}
          </button>
        </div>

        {aiReport && (
          <div className="bg-royal-50 border border-royal-100 p-8 rounded-[2.5rem] relative overflow-hidden shadow-sm animate-slideUp">
             <div className="absolute top-0 right-0 p-10 opacity-5 text-royal-500"><FileText size={160} /></div>
             <div className="flex items-center gap-3 mb-4">
                <span className="bg-royal-500 text-white text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded-lg">AI Financial Insight</span>
             </div>
             <p className="text-xl font-royal text-neutral-800 italic leading-relaxed relative z-10">"{aiReport}"</p>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
           <DataBlock title="Revenue Breakdown">
              <ReportRow label="Gross Possible Income" value={`KES ${totalExpected.toLocaleString()}`} />
              <ReportRow label="Actual Collection" value={`KES ${totalCollected.toLocaleString()}`} />
              <ReportRow label="Arrears Aging" value={`KES ${(totalExpected - totalCollected).toLocaleString()}`} highlight />
           </DataBlock>
           <DataBlock title="Outlay Breakdown">
              <ReportRow label="Maintenance Costs" value={`KES ${maintenanceExpenses.toLocaleString()}`} />
              <ReportRow label="Operating Expenses" value={`KES ${totalExpenses.toLocaleString()}`} />
              <ReportRow label="Net Operating Income" value={`KES ${netIncome.toLocaleString()}`} bold />
           </DataBlock>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-fadeIn">
      {selectedTenant && <TenantIntelligenceModal tenant={selectedTenant} payments={payments.filter(p => p.tenantId === selectedTenant.id)} onClose={() => setSelectedTenant(null)} />}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Collected Rent" value={`KES ${totalCollected.toLocaleString()}`} icon={<Wallet className="text-royal-500" />} trend="up" change="+8.4%" />
        <StatCard title="Total Arrears" value={`KES ${(totalExpected - totalCollected).toLocaleString()}`} icon={<AlertTriangle className="text-red-500" />} trend="down" change="-2.1%" />
        <StatCard title="Portfolio Yield" value={`${occupancyRate.toFixed(1)}%`} icon={<TrendingUp className="text-green-500" />} change="On Target" />
        <StatCard title="Active Units" value={`${houses.length}`} icon={<Home className="text-amber-500" />} change="100% Verified" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-10 rounded-[2.5rem] border border-neutral-200 shadow-sm">
          <h3 className="text-lg font-bold mb-10 text-neutral-800">Financial Growth Pattern</h3>
          <div className="h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={financialData} barSize={60}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#F1F5F9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 11, fill: '#94A3B8', fontWeight: 600}} />
                <YAxis hide />
                <Tooltip cursor={{fill: '#F8FAFC'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' }} />
                <Bar dataKey="amount" radius={[12, 12, 0, 0]}>
                  {financialData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-neutral-900 p-10 rounded-[2.5rem] text-white flex flex-col justify-between shadow-2xl">
           <div>
             <h3 className="text-lg font-bold mb-8">Occupancy Distribution</h3>
             <div className="h-[220px] w-full flex items-center justify-center">
               <ResponsiveContainer width="100%" height="100%">
                 <PieChart>
                   <Pie data={occupancyData} cx="50%" cy="50%" innerRadius={70} outerRadius={90} paddingAngle={8} dataKey="value">
                     {occupancyData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="rgba(0,0,0,0)" />)}
                   </Pie>
                   <Tooltip />
                 </PieChart>
               </ResponsiveContainer>
             </div>
             <div className="space-y-4 mt-8">
               {occupancyData.map((item, idx) => (
                 <div key={item.name} className="flex items-center justify-between">
                   <div className="flex items-center gap-2">
                     <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[idx] }} />
                     <span className="text-xs text-neutral-400 font-medium">{item.name}</span>
                   </div>
                   <span className="text-sm font-bold">{item.value} Units</span>
                 </div>
               ))}
             </div>
           </div>
        </div>
      </div>
    </div>
  );
};

// Internal components
