        <InputGroup icon={<Hash size={16}/>} label="ID Number" placeholder="34567890" value={newTenant.idNumber} onChange={(val) => setNewTenant({...newTenant, idNumber: val})} />
        <InputGroup icon={<Phone size={16}/>} label="Phone Number" placeholder="0712345678" value={newTenant.phoneNumber} onChange={(val) => setNewTenant({...newTenant, phoneNumber: val})} />
        <InputGroup icon={<Users size={16}/>} label="Next of Kin" placeholder="Full Name & Contact" value={newTenant.nextOfKin} onChange={(val) => setNewTenant({...newTenant, nextOfKin: val})} />
        <div className="space-y-2">
          <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest flex items-center gap-2"><MapPin size={14}/> Unit Assignment</label>
          <select required className="w-full bg-neutral-50 border-2 border-neutral-100 p-4 rounded-2xl focus:border-royal-500 outline-none transition-all text-sm font-bold text-neutral-700" value={newTenant.houseNumber} onChange={(e) => setNewTenant({...newTenant, houseNumber: e.target.value})}>
            <option value="">Select Suite</option>
            {houses.map(h => <option key={h.id} value={h.houseNumber} disabled={h.status === HouseStatus.RENTED}>{h.houseNumber} - {h.type}</option>)}
          </select>
        </div>
        <InputGroup icon={<DollarSign size={16}/>} label="Monthly Rent (KES)" type="number" placeholder="35000" value={newTenant.rent.toString()} onChange={(val) => setNewTenant({...newTenant, rent: Number(val)})} />
        <div className="md:col-span-2 pt-6 flex gap-4">
          <button type="button" onClick={onClose} className="flex-1 py-5 rounded-2xl font-black text-xs uppercase tracking-widest text-neutral-400 hover:text-neutral-600 hover:bg-neutral-50 transition-all border border-neutral-200">Cancel</button>
          <button type="submit" className="flex-[2] py-5 rounded-2xl font-black text-xs uppercase tracking-widest text-white bg-royal-500 hover:bg-royal-600 shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-2">Finalize Onboarding <ArrowRight size={16}/></button>
        </div>
      </form>
    </div>
  </div>
);

const InputGroup: React.FC<{ icon: React.ReactNode, label: string, placeholder: string, value: string, onChange: (val: string) => void, type?: string }> = ({ icon, label, placeholder, value, onChange, type = 'text' }) => (
  <div className="space-y-2">
    <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest flex items-center gap-2">{icon} {label}</label>
