const StatusBadge: React.FC<{ status: HouseStatus }> = ({ status }) => {
  const variants = {
    [HouseStatus.RENTED]: 'bg-green-50 text-green-700 border-green-100',
    [HouseStatus.VACANT]: 'bg-amber-50 text-amber-700 border-amber-100',
