const MaintenanceItem: React.FC<{ date: string, task: string, cost: number, house: string }> = ({ date, task, cost, house }) => (
  <div className="flex items-center justify-between p-6 bg-neutral-800 border border-neutral-700 rounded-[2rem] hover:bg-neutral-700 transition-colors">
