    PAID: { color: 'bg-green-100 text-green-700 border-green-200', icon: <CheckCircle2 size={12} />, label: 'PAID' },
    PARTIAL: { color: 'bg-amber-100 text-amber-700 border-amber-200', icon: <Clock size={12} />, label: 'PARTIAL' },
