      {config.icon} {config.label}
    </span>
  );
};

// Modal Components (simplified for brevity, ensuring visual consistency)
const TenantIntelligenceModal: React.FC<{ tenant: Tenant, payments: PaymentRecord[], onClose: () => void }> = ({ tenant, payments, onClose }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'ledger' | 'analysis'>('overview');
