        </div>
        <div className="flex-1 overflow-y-auto p-12 bg-neutral-50/50">
          <div className="flex gap-4 mb-8">
            {(['overview', 'ledger', 'analysis'] as const).map(t => (
              <button key={t} onClick={() => setActiveTab(t)} className={`px-5 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-royal-500 text-white shadow-lg' : 'bg-neutral-200 text-neutral-500 hover:bg-neutral-300'}`}>{t}</button>
            ))}
          </div>
          {activeTab === 'overview' && (
            <div className="space-y-6">
              <div className="grid grid-cols-2 gap-6">
