      onPay({
        id: `pay-${Date.now()}`,
        tenantId: tenant.id,
        amount: paymentAmount,
        date: new Date().toISOString(),
        type: billType,
        reference: `MPESA-${Math.random().toString(36).substring(7).toUpperCase()}`
