import React, { useState, useMemo } from 'react';
import { Tenant, PaymentRecord } from '../types';
import { 
  CreditCard, History, Phone, MessageSquare, CheckCircle, Wallet, Mail, 
  Home, Calendar, ChevronDown, AlertTriangle, X, ShieldCheck, ArrowUpRight, Check,
  Smartphone, Hash, Download, Receipt, User, FileText, Shield, MapPin, ExternalLink,
  Users, ArrowRight, Filter, Search, RotateCcw
} from 'lucide-react';

interface Props {
  tenant: Tenant;
  payments: PaymentRecord[];
  onPay: (payment: PaymentRecord) => void;
}

type TenantTab = 'overview' | 'payments' | 'profile';

export const TenantDashboard: React.FC<Props> = ({ tenant, payments, onPay }) => {
  const [activeTab, setActiveTab] = useState<TenantTab>('overview');
  const [isPaying, setIsPaying] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [billType, setBillType] = useState<PaymentRecord['type']>('TOTAL');
  const [paymentAmount, setPaymentAmount] = useState(tenant.bills.total);

  // Filter States
  const [filterType, setFilterType] = useState<string>('ALL');
  const [filterMethod, setFilterMethod] = useState<string>('ALL');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  const latestPayment = payments.length > 0 ? payments[0] : null;

  const filteredPayments = useMemo(() => {
    return payments.filter(p => {
      const matchesType = filterType === 'ALL' || p.type === filterType;
      const matchesMethod = filterMethod === 'ALL' || p.method === filterMethod;
      const paymentDate = new Date(p.date).getTime();
      const start = startDate ? new Date(startDate).getTime() : 0;
      const end = endDate ? new Date(endDate).getTime() : Infinity;
      const matchesDate = paymentDate >= start && paymentDate <= (end + 86400000); // include full end day
      return matchesType && matchesMethod && matchesDate;
    });
  }, [payments, filterType, filterMethod, startDate, endDate]);

  const handleBillTypeChange = (type: PaymentRecord['type']) => {
    setBillType(type);
    if (type === 'RENT') setPaymentAmount(tenant.bills.rent);
    else if (type === 'WATER') setPaymentAmount(tenant.bills.water);
    else if (type === 'GARBAGE') setPaymentAmount(tenant.bills.garbage);
    else setPaymentAmount(tenant.bills.total);
  };

  const handleInitiatePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (paymentAmount > 0) {
      setShowConfirm(true);
    }
  };

  const resetFilters = () => {
    setFilterType('ALL');
    setFilterMethod('ALL');
    setStartDate('');
    setEndDate('');
  };

  const simulatePayment = () => {
    setShowConfirm(false);
    setIsPaying(true);
    setTimeout(() => {
      onPay({
        id: `pay-${Date.now()}`,
        tenantId: tenant.id,
        amount: paymentAmount,
        date: new Date().toISOString(),
        type: billType,
        reference: `MPESA-${Math.random().toString(36).substring(7).toUpperCase()}`,
        method: 'M-Pesa'
      });
      setIsPaying(false);
    }, 2000);
  };

  return (
    <div className="space-y-8 animate-fadeIn font-sans">
      {showConfirm && <PaymentConfirmationModal amount={paymentAmount} billType={billType} phone={tenant.phoneNumber} onCancel={() => setShowConfirm(false)} onConfirm={simulatePayment} />}

      {/* Internal Navigation */}
      <div className="flex bg-white p-1.5 rounded-2xl border border-neutral-200 shadow-sm w-fit">
        {(['overview', 'payments', 'profile'] as const).map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
              activeTab === tab 
                ? 'bg-royal-500 text-white shadow-lg shadow-royal-500/20' 
                : 'text-neutral-400 hover:text-neutral-600'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {activeTab === 'overview' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
          <div className="lg:col-span-2 space-y-8">
            {/* Tenant Greeting Card */}
            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-10 opacity-0 group-hover:opacity-10 transition-opacity duration-1000 text-royal-500"><ShieldCheck size={160} /></div>
               <div className="relative z-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
                  <div>
                     <span className="text-royal-500 text-[10px] font-black uppercase tracking-[0.4em] mb-4 block">Resident Portal</span>
                     <h2 className="text-5xl font-royal text-neutral-900 font-black tracking-tight leading-tight">Jambo, {tenant.name.split(' ')[0]}</h2>
                     <div className="flex flex-wrap gap-4 mt-8">
                        <ProfileBadge icon={<Phone size={12}/>} value={tenant.phoneNumber} />
                        <ProfileBadge icon={<Home size={12}/>} value={`Unit ${tenant.houseNumber}`} active />
                     </div>
                  </div>
                  <div className="text-left md:text-right border-t md:border-t-0 pt-6 md:pt-0 border-neutral-100">
                     <div className="text-[10px] text-neutral-400 uppercase font-black tracking-widest mb-1.5 flex items-center md:justify-end gap-1"><Calendar size={12}/> Cycle Renew</div>
                     <div className="text-lg font-bold text-neutral-800">1st Nov 2024</div>
