               </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
               <BillCard title="Total Arrears" amount={tenant.bills.total} icon={<Wallet className="text-royal-500" />} urgent={tenant.bills.total > 0} />
               {latestPayment ? (
                 <div className="p-8 rounded-[2.5rem] border border-green-100 bg-green-50 shadow-sm flex flex-col justify-between cursor-pointer hover:border-green-300 transition-all" onClick={() => setActiveTab('payments')}>
                   <div className="flex justify-between items-start mb-4">
