export enum UserRole {
  TENANT = 'TENANT',
  CARETAKER = 'CARETAKER',
  LANDLORD = 'LANDLORD'
}

export enum HouseStatus {
  VACANT = 'VACANT',
  RENTED = 'RENTED',
  UNDER_REPAIR = 'UNDER_REPAIR'
}

export interface Bill {
  rent: number;
  water: number;
  garbage: number;
  total: number;
  status: 'PAID' | 'UNPAID' | 'PARTIAL';
}

export interface Lease {
  startDate: string;
  endDate: string;
  depositAmount: number;
  depositStatus: 'HELD' | 'REFUNDED' | 'FORFEITED';
  status: 'ACTIVE' | 'EXPIRED' | 'TERMINATED';
}

export interface Incident {
  id: string;
  date: string;
  type: 'LEASE_RENEWAL' | 'LATE_PAYMENT' | 'MAINTENANCE_ISSUE' | 'COMPLIANCE' | 'NOTE';
  description: string;
  severity: 'low' | 'medium' | 'high';
}

export interface Tenant {
  id: string;
  name: string;
  email: string;
  houseNumber: string;
  idNumber: string;
  phoneNumber: string;
  nextOfKin: string;
  agreementUrl?: string;
  bills: Bill;
  joinDate: string;
  lease?: Lease;
  incidents?: Incident[];
}

export interface PastTenant {
  name: string;
  period: string;
  exitReason: string;
}

export interface House {
  id: string;
  houseNumber: string;
  type: 'Studio' | '1 Bedroom' | '2 Bedroom' | 'Penthouse';
  status: HouseStatus;
  lastVacantDate: string;
  repairs: Repair[];
  totalEarnings: number;
  tenantHistory: PastTenant[];
}

export interface Repair {
  id: string;
  date: string;
  description: string;
  cost: number;
  category: string;
}

export interface Expense {
  id: string;
  date: string;
  category: 'MAINTENANCE' | 'UTILITIES' | 'TAX' | 'LEGAL' | 'SALARY' | 'OTHER';
  amount: number;
  description: string;
  propertyId?: string;
  unitId?: string;
}

export interface PaymentRecord {
  id: string;
  tenantId: string;
  amount: number;
  date: string;
  type: 'RENT' | 'WATER' | 'GARBAGE' | 'TOTAL';
  reference: string;
  method: string;
}

export interface Owner {
  id: string;
  name: string;
  balance: number;
  managementFeeRate: number;
}

