import React, { useState, useMemo } from 'react';
import { Tenant, PaymentRecord, Incident } from '../types';
import { 
  CreditCard, History, Phone, MessageSquare, CheckCircle, Wallet, Mail, 
  Home, Calendar, ChevronDown, AlertTriangle, X, ShieldCheck, ArrowUpRight, Check,
  Smartphone, Hash, Download, Receipt, User, FileText, Shield, MapPin, ExternalLink,
  Users, ArrowRight, Filter, Search, RotateCcw, Landmark, PiggyBank, Info,
  AlertCircle, ShieldAlert, FileClock, Wrench
} from 'lucide-react';

interface Props {
  tenant: Tenant;
  payments: PaymentRecord[];
  onPay: (payment: PaymentRecord) => void;
}

type TenantTab = 'overview' | 'payments' | 'profile';

export const TenantDashboard: React.FC<Props> = ({ tenant, payments, onPay }) => {
  const [activeTab, setActiveTab] = useState<TenantTab>('overview');
  const [isPaying, setIsPaying] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [billType, setBillType] = useState<PaymentRecord['type']>('TOTAL');
  const [paymentAmount, setPaymentAmount] = useState(tenant.bills.total);

  // Filter States
  const [filterType, setFilterType] = useState<string>('ALL');
  const [filterMethod, setFilterMethod] = useState<string>('ALL');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  const latestPayment = payments.length > 0 ? payments[0] : null;

  const totalLifetimePaid = useMemo(() => {
    return payments.reduce((acc, p) => acc + p.amount, 0);
  }, [payments]);

  const filteredPayments = useMemo(() => {
    return payments.filter(p => {
      const matchesType = filterType === 'ALL' || p.type === filterType;
      const matchesMethod = filterMethod === 'ALL' || p.method === filterMethod;
      const paymentDate = new Date(p.date).getTime();
      const start = startDate ? new Date(startDate).getTime() : 0;
      const end = endDate ? new Date(endDate).getTime() : Infinity;
      const matchesDate = paymentDate >= start && paymentDate <= (end + 86400000); // include full end day
      return matchesType && matchesMethod && matchesDate;
    });
  }, [payments, filterType, filterMethod, startDate, endDate]);

  const handleBillTypeChange = (type: PaymentRecord['type']) => {
    setBillType(type);
    if (type === 'RENT') setPaymentAmount(tenant.bills.rent);
    else if (type === 'WATER') setPaymentAmount(tenant.bills.water);
    else if (type === 'GARBAGE') setPaymentAmount(tenant.bills.garbage);
    else setPaymentAmount(tenant.bills.total);
  };

  const handleInitiatePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (paymentAmount > 0) {
      setShowConfirm(true);
    }
  };

  const resetFilters = () => {
    setFilterType('ALL');
    setFilterMethod('ALL');
    setStartDate('');
    setEndDate('');
  };

  const simulatePayment = () => {
    setShowConfirm(false);
    setIsPaying(true);
    setTimeout(() => {
      onPay({
        id: `pay-${Date.now()}`,
        tenantId: tenant.id,
        amount: paymentAmount,
        date: new Date().toISOString(),
        type: billType,
        reference: `MPESA-${Math.random().toString(36).substring(7).toUpperCase()}`,
        method: 'M-Pesa'
      });
      setIsPaying(false);
    }, 2000);
  };

  return (
    <div className="space-y-8 animate-fadeIn font-sans">
      {showConfirm && <PaymentConfirmationModal amount={paymentAmount} billType={billType} phone={tenant.phoneNumber} onCancel={() => setShowConfirm(false)} onConfirm={simulatePayment} />}

      {/* Internal Navigation */}
      <div className="flex bg-white p-1.5 rounded-2xl border border-neutral-200 shadow-sm w-fit">
        {(['overview', 'payments', 'profile'] as const).map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`px-8 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
              activeTab === tab 
                ? 'bg-royal-500 text-white shadow-lg shadow-royal-500/20' 
                : 'text-neutral-400 hover:text-neutral-600'
            }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {activeTab === 'overview' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
          <div className="lg:col-span-2 space-y-8">
            {/* Tenant Greeting Card */}
            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm relative overflow-hidden group">
               <div className="absolute top-0 right-0 p-10 opacity-0 group-hover:opacity-10 transition-opacity duration-1000 text-royal-500"><ShieldCheck size={160} /></div>
               <div className="relative z-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
                  <div>
                     <span className="text-royal-500 text-[10px] font-black uppercase tracking-[0.4em] mb-4 block">Resident Portal</span>
                     <h2 className="text-5xl font-royal text-neutral-900 font-black tracking-tight leading-tight">Jambo, {tenant.name.split(' ')[0]}</h2>
                     <div className="flex flex-wrap gap-4 mt-8">
                        <ProfileBadge icon={<Phone size={12}/>} value={tenant.phoneNumber} />
                        <ProfileBadge icon={<Home size={12}/>} value={`Unit ${tenant.houseNumber}`} active />
                     </div>
                  </div>
                  <div className="text-left md:text-right border-t md:border-t-0 pt-6 md:pt-0 border-neutral-100">
                     <div className="text-[10px] text-neutral-400 uppercase font-black tracking-widest mb-1.5 flex items-center md:justify-end gap-1"><Calendar size={12}/> Cycle Renew</div>
                     <div className="text-lg font-bold text-neutral-800">1st Nov 2024</div>
                  </div>
               </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
               <BillCard title="Total Arrears" amount={tenant.bills.total} icon={<Wallet className="text-royal-500" />} urgent={tenant.bills.total > 0} />
               {latestPayment ? (
                 <div className="p-8 rounded-[2.5rem] border border-green-100 bg-green-50 shadow-sm flex flex-col justify-between cursor-pointer hover:border-green-300 transition-all" onClick={() => setActiveTab('payments')}>
                   <div className="flex justify-between items-start mb-4">
                     <span className="text-[10px] font-black uppercase tracking-widest text-green-600">Latest Payment</span>
                     <div className="p-2 bg-white rounded-xl text-green-500 shadow-sm"><Check size={16}/></div>
                   </div>
                   <div>
                     <div className="text-2xl font-bold text-green-800 tracking-tighter">KES {latestPayment.amount.toLocaleString()}</div>
                     <div className="text-[10px] text-green-600 font-bold uppercase tracking-tight mt-1">{latestPayment.type} • {new Date(latestPayment.date).toLocaleDateString()}</div>
                   </div>
                 </div>
               ) : (
                 <BillCard title="House Rent" amount={tenant.bills.rent} icon={<Home className="text-indigo-500" />} />
               )}
               <BillCard title="Water Meter" amount={tenant.bills.water} icon={<div className="w-2.5 h-2.5 rounded-full bg-cyan-400" />} />
               <BillCard title="Service Fee" amount={tenant.bills.garbage} icon={<div className="w-2.5 h-2.5 rounded-full bg-green-400" />} />
            </div>

            {/* Quick Summary Ledger */}
            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
               <div className="flex justify-between items-center mb-10">
                  <h3 className="text-lg font-bold text-neutral-800 flex items-center gap-3"><History size={20} className="text-royal-500" /> Recent Activity</h3>
                  <button onClick={() => setActiveTab('payments')} className="text-royal-500 text-[10px] font-black uppercase tracking-widest flex items-center gap-2 hover:bg-royal-50 px-4 py-2 rounded-xl transition-all border border-royal-100">
                    See Full History <ArrowUpRight size={14}/>
                  </button>
               </div>
               {payments.length === 0 ? (
                 <div className="py-20 text-center space-y-4">
                    <div className="w-16 h-16 bg-neutral-50 rounded-full flex items-center justify-center mx-auto text-neutral-300"><History size={32}/></div>
                    <p className="text-neutral-400 font-medium italic">No transactions found for the current billing cycle.</p>
                 </div>
               ) : (
                 <div className="space-y-4">
                   {payments.slice(0, 3).map(p => (
                     <div key={p.id} className="flex flex-col sm:flex-row sm:items-center justify-between p-6 bg-neutral-50 rounded-[2rem] border border-neutral-100 hover:border-royal-200 transition-all group gap-4 relative overflow-hidden">
                        <div className="flex items-center gap-5 relative z-10">
                          <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center text-[#32ba43] shadow-sm border border-neutral-100 group-hover:scale-105 transition-transform"><Check size={24} strokeWidth={3}/></div>
                          <div>
                            <div className="flex items-center gap-2">
                               <span className="font-black text-neutral-900 text-sm tracking-tight">{p.type} PAYMENT</span>
                               <span className="bg-green-100 text-green-700 text-[8px] font-black px-2 py-0.5 rounded-full uppercase">Success</span>
                            </div>
                            <div className="text-xs text-neutral-500 font-medium mt-1">{new Date(p.date).toLocaleDateString()} • {p.method}</div>
                          </div>
                        </div>
                        <div className="text-2xl font-black text-neutral-900 tracking-tighter sm:text-right">
                           <span className="text-xs font-medium opacity-30 mr-1">KES</span>
                           {p.amount.toLocaleString()}
                        </div>
                     </div>
                   ))}
                 </div>
               )}
            </div>
          </div>

          {/* Payment Terminal Side Rail */}
          <div className="space-y-8">
            <div className="bg-neutral-900 text-white p-10 rounded-[3.5rem] shadow-2xl relative overflow-hidden flex flex-col justify-between h-[600px] group border border-neutral-800">
               <div className="absolute top-0 right-0 p-10 opacity-0 group-hover:opacity-10 transition-opacity duration-700 text-royal-500"><CreditCard size={180} /></div>
