                       <th className="px-6 py-4 text-[10px] font-black text-neutral-400 uppercase">Reference</th>
                       <th className="px-6 py-4 text-[10px] font-black text-neutral-400 uppercase text-right">Amount</th>
                     </tr>
                   </thead>
                   <tbody className="divide-y divide-neutral-50">
                     {filteredPayments.map(p => (
                       <tr key={p.id} className="hover:bg-neutral-50/50 transition-colors">
