  tenantHistory: PastTenant[];
}

export interface Repair {
  id: string;
  date: string;
  description: string;
  cost: number;
  category: string;
}

export interface Expense {
  id: string;
  date: string;
  category: 'MAINTENANCE' | 'UTILITIES' | 'TAX' | 'LEGAL' | 'SALARY' | 'OTHER';
  amount: number;
  description: string;
  propertyId?: string;
  unitId?: string;
}

export interface PaymentRecord {
  id: string;
  tenantId: string;
  amount: number;
  date: string;
  type: 'RENT' | 'WATER' | 'GARBAGE' | 'TOTAL';
  reference: string;
  method: string;
}

export interface Owner {
  id: string;
  name: string;
  balance: number;
  managementFeeRate: number;
}

