      <div className="text-2xl font-bold font-royal truncate tracking-tight">{value}</div>
    </div>
  );
};

const ReportRow: React.FC<{ label: string, value: string, highlight?: boolean, bold?: boolean }> = ({ label, value, highlight, bold }) => (
  <div className={`flex justify-between items-center py-4 border-b border-neutral-50 last:border-0 ${bold ? 'pt-8 border-neutral-200' : ''}`}>
    <span className={`text-sm font-medium ${bold ? 'text-neutral-900 font-black uppercase text-[10px] tracking-widest' : 'text-neutral-500'}`}>{label}</span>
    <span className={`text-sm font-bold ${highlight ? 'text-red-500' : 'text-neutral-800'} ${bold ? 'text-2xl font-royal' : 'font-royal'}`}>{value}</span>
  </div>
);

const TenantIntelligenceModal: React.FC<{ tenant: Tenant, payments: PaymentRecord[], onClose: () => void }> = ({ tenant, payments, onClose }) => {
  const [activeTab, setActiveTab] = useState<'overview' | 'ledger' | 'analysis'>('overview');
  const [aiInsight, setAiInsight] = useState<string | null>(null);
