              <h2 className="text-5xl font-royal text-royal-100 font-black tracking-tight">{tenant.name}</h2>
              <div className="flex items-center gap-4 mt-4 text-neutral-400 text-sm font-medium">
                <div className="flex items-center gap-1.5"><Home size={16}/> Unit {tenant.houseNumber}</div>
                <div className="w-1.5 h-1.5 rounded-full bg-neutral-700" />
                <div className="flex items-center gap-1.5"><Clock size={16}/> Joined {tenant.joinDate}</div>
              </div>
            </div>
            <button onClick={onClose} className="p-4 bg-white/5 hover:bg-white/10 rounded-2xl transition-all"><X size={28} /></button>
