          <div className="flex gap-4 mt-10">
            <ModalTab active={activeTab === 'overview'} onClick={() => setActiveTab('overview')} label="Financials" />
            <ModalTab active={activeTab === 'ledger'} onClick={() => setActiveTab('ledger')} label="Payments" />
            <ModalTab active={activeTab === 'analysis'} onClick={() => setActiveTab('analysis')} label="AI Audit" />
          </div>
