                <MetricBox label="Collected to Date" value={`KES ${totalPaid.toLocaleString()}`} color="green" />
                <MetricBox label="Current Balance" value={`KES ${tenant.bills.total.toLocaleString()}`} color="red" />
                <MetricBox label="Next Cycle" value="1st Nov 2024" color="blue" />
