              <div className="bg-white p-10 rounded-[2.5rem] border border-neutral-200 shadow-sm">
                 <div className="space-y-6">
                    <ReportRow label="Monthly Base Rent" value={`KES ${tenant.bills.rent.toLocaleString()}`} />
                    <ReportRow label="Water Utility" value={`KES ${tenant.bills.water.toLocaleString()}`} />
                    <ReportRow label="Fixed Service Levy" value={`KES ${tenant.bills.garbage.toLocaleString()}`} />
                    <ReportRow label="Total Outstanding" value={`KES ${tenant.bills.total.toLocaleString()}`} bold highlight />
                 </div>
              </div>
            </div>
          )}
          {activeTab === 'ledger' && (
            <div className="bg-white rounded-[2rem] border border-neutral-200 overflow-hidden shadow-sm">
               <table className="w-full text-left text-sm">
                  <thead className="bg-neutral-50 border-b">
                    <tr>
                      <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Date</th>
                      <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Reference</th>
                      <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Allocation</th>
                      <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Amount</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-neutral-50">
                    {payments.map(p => (
                      <tr key={p.id} className="hover:bg-neutral-50 transition-colors">
                        <td className="px-8 py-6">{new Date(p.date).toLocaleDateString()}</td>
                        <td className="px-8 py-6 font-mono text-xs text-neutral-500">{p.reference}</td>
                        <td className="px-8 py-6 text-[10px] font-black uppercase text-neutral-400">{p.type}</td>
                        <td className="px-8 py-6 text-right font-bold text-green-600">KES {p.amount.toLocaleString()}</td>
                      </tr>
                    ))}
                    {payments.length === 0 && <tr><td colSpan={4} className="p-20 text-center text-neutral-300 italic">No historical transactions recorded.</td></tr>}
                  </tbody>
               </table>
            </div>
          )}
          {activeTab === 'analysis' && (
            <div className="bg-neutral-900 p-16 rounded-[3rem] text-center space-y-10 shadow-2xl relative overflow-hidden group">
              <div className="absolute inset-0 bg-gradient-to-br from-royal-500/10 to-transparent pointer-events-none" />
              <div className="relative z-10 max-w-md mx-auto space-y-4">
                  <Activity className="text-royal-500 mx-auto" size={48} />
                  <h4 className="text-white text-2xl font-royal font-bold">Risk Behavioral Scan</h4>
                  <p className="text-neutral-400 text-sm leading-relaxed">AI analysis of payment periodicity and historical consistency.</p>
                  {aiInsight ? (
                    <div className="mt-10 bg-white/5 p-8 rounded-[2rem] border border-white/10 text-left animate-fadeIn">
                       <p className="text-neutral-200 italic leading-relaxed text-lg font-royal">"{aiInsight}"</p>
                    </div>
                  ) : (
                    <button onClick={handleRunAnalysis} disabled={loadingAI} className="mt-10 bg-royal-500 text-white px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:bg-royal-600 shadow-xl active:scale-95 transition-all">
                      {loadingAI ? 'Calculating...' : 'Run Behavioral Audit'}
                    </button>
                  )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Tenant, House, HouseStatus, PaymentRecord } from '../types';
import { 
  UserPlus, Droplets, Send, Wrench, RefreshCw, X, User, Phone, Mail, 
  Hash, Home, CheckCircle2, CircleDashed, Hammer, Users, AlertTriangle, Clock, 
  History, DollarSign, Activity, Eye, Search, MapPin, ArrowRight, Save, Smartphone,
  Receipt, Calendar, ChevronRight, Filter, RotateCcw, Check
} from 'lucide-react';
import { generateTenantNotification, analyzeTenantFinancials } from '../services/geminiService';

interface Props {
  tenants: Tenant[];
  houses: House[];
  payments: PaymentRecord[];
  onAddTenant: (t: Tenant) => void;
  onUpdateBills: (id: string, currentReading: number) => void;
  onUpdateHouse: (id: string, status: HouseStatus) => void;
  activeTab?: string;
}

export const CaretakerDashboard: React.FC<Props> = ({ 
  tenants, houses, payments, onAddTenant, onUpdateBills, onUpdateHouse,
  activeTab: propTab 
}) => {
  const [activeTab, setActiveTab] = useState<'houses' | 'tenants' | 'billing'>('houses');
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedHouse, setSelectedHouse] = useState<House | null>(null);
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [loadingAI, setLoadingAI] = useState<string | null>(null);
  const [updatedTenantId, setUpdatedTenantId] = useState<string | null>(null);

  // Local state for pending meter readings
  const [pendingReadings, setPendingReadings] = useState<Record<string, number>>({});

  // Billing Filter States
  const [billFilterType, setBillFilterType] = useState<string>('ALL');
  const [billFilterMethod, setBillFilterMethod] = useState<string>('ALL');
  const [billStartDate, setBillStartDate] = useState<string>('');
  const [billEndDate, setBillEndDate] = useState<string>('');

  useEffect(() => {
    if (propTab) {
      if (propTab === 'houses' || propTab === 'properties') setActiveTab('houses');
      else if (propTab === 'tenants') setActiveTab('tenants');
      else if (propTab === 'billing' || propTab === 'payments') setActiveTab('billing');
    }
  }, [propTab]);

  const [newTenant, setNewTenant] = useState({
    name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0
  });

  const filteredCollections = useMemo(() => {
    return payments.filter(p => {
      const matchesType = billFilterType === 'ALL' || p.type === billFilterType;
      const matchesMethod = billFilterMethod === 'ALL' || p.method === billFilterMethod;
      const paymentDate = new Date(p.date).getTime();
      const start = billStartDate ? new Date(billStartDate).getTime() : 0;
      const end = billEndDate ? new Date(billEndDate).getTime() : Infinity;
      const matchesDate = paymentDate >= start && paymentDate <= (end + 86400000);
      return matchesType && matchesMethod && matchesDate;
    });
  }, [payments, billFilterType, billFilterMethod, billStartDate, billEndDate]);

  const handleSendReminder = async (tenant: Tenant) => {
    setLoadingAI(tenant.id);
    try {
      const message = await generateTenantNotification(tenant.name, tenant.bills.total);
      alert(`AI Reminder for ${tenant.name}:\n\n"${message}"\n\nNotification sent to ${tenant.phoneNumber}`);
    } catch (err) { console.error(err); }
    finally { setLoadingAI(null); }
  };

  const handleRegisterTenant = (e: React.FormEvent) => {
    e.preventDefault();
    const tenant: Tenant = {
      id: `t-${Date.now()}`,
      name: newTenant.name,
      email: newTenant.email,
      houseNumber: newTenant.houseNumber,
      idNumber: newTenant.idNumber,
      phoneNumber: newTenant.phoneNumber,
      nextOfKin: newTenant.nextOfKin,
      joinDate: new Date().toISOString().split('T')[0],
      bills: { 
        rent: newTenant.rent, 
        water: 0, 
        prevWaterReading: 0,
        currWaterReading: 0,
        garbage: 500, 
        total: newTenant.rent + 500, 
        status: 'UNPAID' 
      }
    };
    onAddTenant(tenant);
    setShowAddModal(false);
    setNewTenant({ name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0 });
  };

  const handleManualBillUpdate = (tenantId: string) => {
    const reading = pendingReadings[tenantId];
    if (reading === undefined) return;

    onUpdateBills(tenantId, reading);
    setUpdatedTenantId(tenantId);

    // Clear pending for this tenant after a short delay for feedback
    setTimeout(() => {
      setUpdatedTenantId(null);
      setPendingReadings(prev => {
        const next = { ...prev };
        delete next[tenantId];
        return next;
      });
    }, 1500);
  };

  const resetBillFilters = () => {
    setBillFilterType('ALL');
    setBillFilterMethod('ALL');
    setBillStartDate('');
    setBillEndDate('');
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {showAddModal && <AddTenantModal houses={houses} newTenant={newTenant} setNewTenant={setNewTenant} onClose={() => setShowAddModal(false)} onSubmit={handleRegisterTenant} />}
      {selectedHouse && (
        <HouseDetailModal 
          house={selectedHouse} 
          onClose={() => setSelectedHouse(null)} 
          currentTenant={tenants.find(t => t.houseNumber === selectedHouse.houseNumber)} 
          onViewTenant={(t) => {
            setSelectedHouse(null);
            setSelectedTenant(t);
          }}
        />
      )}
      {selectedTenant && <TenantIntelligenceModal tenant={selectedTenant} payments={payments.filter(p => p.tenantId === selectedTenant.id)} onClose={() => setSelectedTenant(null)} />}

      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-royal text-neutral-900 font-bold">Caretaker Operations</h2>
          <p className="text-neutral-400 text-sm mt-1">Daily unit management and property logistics</p>
        </div>
        <div className="flex bg-neutral-100 p-1.5 rounded-2xl border border-neutral-200 shadow-sm">
          {(['houses', 'tenants', 'billing'] as const).map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-white text-royal-500 shadow-sm' : 'text-neutral-400 hover:text-neutral-600'}`}>
              {tab === 'houses' ? 'Properties' : tab === 'billing' ? 'Collections' : tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'houses' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {houses.map(house => (
            <UnitCard key={house.id} house={house} onUpdate={onUpdateHouse} onView={() => setSelectedHouse(house)} />
          ))}
          <button onClick={() => setShowAddModal(true)} className="border-2 border-dashed border-neutral-200 rounded-[2.5rem] flex flex-col items-center justify-center p-12 text-neutral-400 hover:border-royal-400 hover:text-royal-500 hover:bg-royal-50 transition-all group min-h-[300px] shadow-sm">
            <div className="bg-neutral-50 group-hover:bg-royal-100 p-6 rounded-3xl mb-4 transition-colors"><UserPlus size={40} /></div>
            <span className="font-black text-xs uppercase tracking-widest">Register Resident</span>
          </button>
        </div>
      )}

      {activeTab === 'tenants' && (
        <div className="bg-white rounded-[2.5rem] border border-neutral-200 shadow-sm overflow-hidden animate-slideUp">
          <div className="p-8 border-b border-neutral-100 flex justify-between items-center">
             <h3 className="font-bold text-lg text-neutral-800">Resident Registry</h3>
             <div className="relative">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400" />
                <input type="text" placeholder="Search residents..." className="pl-9 pr-4 py-2 bg-neutral-50 border border-neutral-200 rounded-xl text-xs outline-none focus:border-royal-500 transition-all" />
             </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-neutral-50 border-b">
                <tr>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Resident</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Unit No</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Last Payment</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Bill Status</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-neutral-50">
                {tenants.map(t => {
                  const tPayments = payments.filter(p => p.tenantId === t.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
                  const lastPayment = tPayments[0];

                  return (
                    <tr key={t.id} className="hover:bg-neutral-50 transition-all group">
                      <td className="px-8 py-6">
                        <div className="font-bold text-neutral-800 group-hover:text-royal-500 transition-colors">{t.name}</div>
                        <div className="text-[10px] text-neutral-400 font-medium tracking-tight flex items-center gap-1"><Phone size={10}/> {t.phoneNumber}</div>
                      </td>
                      <td className="px-8 py-6 font-bold text-neutral-600">{t.houseNumber}</td>
                      <td className="px-8 py-6">
                        {lastPayment ? (
                          <div>
                            <div className="text-xs font-black text-neutral-800">KES {lastPayment.amount.toLocaleString()}</div>
                            <div className="text-[9px] text-neutral-400 font-bold uppercase">{new Date(lastPayment.date).toLocaleDateString()}</div>
                          </div>
                        ) : (
                          <span className="text-[10px] text-neutral-300 italic font-medium">No records</span>
                        )}
                      </td>
                      <td className="px-8 py-6"><BillStatusBadge status={t.bills.status} /></td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex justify-end gap-3">
                          <button onClick={() => setSelectedTenant(t)} className="p-2.5 bg-neutral-100 hover:bg-neutral-200 text-neutral-500 rounded-xl transition-all"><Eye size={16} /></button>
                          <button onClick={() => handleSendReminder(t)} disabled={loadingAI === t.id} className="inline-flex items-center gap-2 bg-royal-500 hover:bg-royal-600 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-royal-500/20 disabled:opacity-50 active:scale-95 transition-all">
                            {loadingAI === t.id ? <Activity className="animate-spin" size={14}/> : <Send size={14}/>} Notify
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'billing' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-8">
            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm relative overflow-hidden">
              <div className="flex items-center justify-between mb-10">
                 <div>
                   <h3 className="text-2xl font-royal font-bold flex items-center gap-3 text-neutral-900"><Droplets className="text-cyan-500" /> Water Meter Portal</h3>
                   <p className="text-neutral-400 text-xs font-medium mt-1">Record utility consumption & update billing cycles</p>
                 </div>
                 <div className="bg-cyan-50 text-cyan-700 px-4 py-2 rounded-2xl border border-cyan-100 text-[10px] font-black uppercase tracking-widest">
                   Rate: KES 150 / Unit
                 </div>
              </div>

              <div className="space-y-6">
                {tenants.map(t => {
                  const pendingValue = pendingReadings[t.id];
                  const displayValue = pendingValue !== undefined ? pendingValue : t.bills.currWaterReading;
                  const isModified = pendingValue !== undefined && pendingValue !== t.bills.currWaterReading;
                  const unitsUsed = Math.max(0, displayValue - t.bills.prevWaterReading);
                  const calculatedCost = unitsUsed * 150;

                  return (
                    <div key={t.id} className={`flex flex-col sm:flex-row sm:items-center justify-between p-8 rounded-[2.5rem] border-2 transition-all group ${isModified ? 'border-royal-200 bg-royal-50/30' : 'border-neutral-50 bg-neutral-50/50 hover:bg-white hover:border-neutral-100'}`}>
                      <div className="mb-4 sm:mb-0">
                        <div className="flex items-center gap-2 mb-1">
                          <span className="bg-neutral-900 text-white text-[8px] font-black px-2 py-0.5 rounded-md uppercase tracking-widest">Unit {t.houseNumber}</span>
                          <span className="text-[10px] font-black text-neutral-400 uppercase">Prev: {t.bills.prevWaterReading}</span>
                        </div>
                        <div className="font-bold text-neutral-800 text-lg">{t.name}</div>
                        {isModified && (
                          <div className="text-[9px] font-black text-royal-500 uppercase flex items-center gap-1 mt-1 animate-pulse">
                            <Activity size={10}/> Pending Update
                          </div>
                        )}
                      </div>

                      <div className="flex items-center gap-4">
                        <div className="text-right">
                          <label className="text-[9px] font-black text-neutral-400 uppercase tracking-widest block mb-1">Current Reading</label>
                          <div className="flex items-center gap-2">
                            <input 
                              type="number" 
                              value={displayValue}
                              onChange={(e) => setPendingReadings(prev => ({ ...prev, [t.id]: Number(e.target.value) }))}
                              className={`w-28 p-3 text-center text-lg font-black bg-white border-2 rounded-2xl focus:border-royal-500 outline-none transition-all ${updatedTenantId === t.id ? 'border-green-500 text-green-600' : 'border-neutral-200 text-neutral-800'}`} 
                            />
                            {isModified ? (
                              <button 
                                onClick={() => handleManualBillUpdate(t.id)}
                                className="p-4 bg-royal-500 text-white rounded-2xl shadow-lg shadow-royal-500/30 hover:bg-royal-600 active:scale-90 transition-all"
                                title="Accept & Calculate Bill"
                              >
                                <Check size={20} strokeWidth={3} />
                              </button>
                            ) : updatedTenantId === t.id ? (
                              <div className="p-4 bg-green-500 text-white rounded-2xl shadow-lg shadow-green-500/30 animate-bounce">
                                <Save size={20} />
                              </div>
                            ) : null}
                          </div>
                        </div>

                        <div className="min-w-[100px] text-right">
                           <div className="text-[9px] font-black text-neutral-400 uppercase mb-1">Total Due</div>
                           <div className="text-xl font-black text-neutral-900 tracking-tighter">
                             <span className="text-[10px] mr-1 opacity-30">KES</span>
                             {calculatedCost.toLocaleString()}
                           </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
              <div className="flex flex-col gap-6 mb-8">
                <h3 className="text-xl font-bold flex items-center gap-3"><History className="text-royal-500" /> Collection Logs</h3>

                {/* Advanced Filtering UI for Caretaker */}
                <div className="bg-neutral-50 p-6 rounded-[2rem] border border-neutral-100 grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-neutral-400 uppercase tracking-widest pl-1">Method & Category</label>
                    <div className="flex gap-2">
                      <select 
                        value={billFilterMethod}
                        onChange={(e) => setBillFilterMethod(e.target.value)}
                        className="flex-1 bg-white border border-neutral-200 rounded-lg px-2 py-2 text-[10px] font-bold outline-none"
                      >
                        <option value="ALL">All Methods</option>
                        <option value="M-Pesa">M-Pesa</option>
                        <option value="Bank">Bank</option>
                      </select>
                      <select 
                        value={billFilterType}
                        onChange={(e) => setBillFilterType(e.target.value)}
                        className="flex-1 bg-white border border-neutral-200 rounded-lg px-2 py-2 text-[10px] font-bold outline-none"
                      >
                        <option value="ALL">All Types</option>
                        <option value="RENT">Rent</option>
                        <option value="WATER">Water</option>
                      </select>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-neutral-400 uppercase tracking-widest pl-1">Date Period</label>
                    <div className="flex gap-2">
                      <input type="date" value={billStartDate} onChange={e => setBillStartDate(e.target.value)} className="flex-1 bg-white border border-neutral-200 rounded-lg px-2 py-2 text-[10px] font-bold outline-none" />
                      <button onClick={resetBillFilters} className="bg-neutral-200 hover:bg-neutral-300 p-2 rounded-lg text-neutral-500 transition-all"><RotateCcw size={14}/></button>
                    </div>
                  </div>
                </div>
              </div>

              <div className="space-y-4 max-h-[400px] overflow-y-auto scrollbar-hide">
                {filteredCollections.length === 0 ? (
                  <div className="py-20 text-center text-neutral-300 text-xs italic">No collections found matching filters.</div>
                ) : (
                  filteredCollections.map(p => {
