                        <div className="flex justify-end gap-3">
                          <button onClick={() => setSelectedTenant(t)} className="p-2.5 bg-neutral-100 hover:bg-neutral-200 text-neutral-500 rounded-xl transition-all"><Eye size={16} /></button>
                          <button onClick={() => handleSendReminder(t)} disabled={loadingAI === t.id} className="inline-flex items-center gap-2 bg-royal-500 hover:bg-royal-600 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-royal-500/20 disabled:opacity-50 active:scale-95 transition-all">
                            {loadingAI === t.id ? <Activity className="animate-spin" size={14}/> : <Send size={14}/>} Notify
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'billing' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-8">
            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
              <div className="flex items-center justify-between mb-8">
                <h3 className="text-xl font-bold flex items-center gap-3"><Droplets className="text-cyan-500" /> Utility Meters</h3>
                <span className="bg-cyan-50 text-cyan-600 text-[10px] font-black px-3 py-1.5 rounded-lg border border-cyan-100 uppercase tracking-widest">Rate: 150/unit</span>
              </div>

              <div className="space-y-4">
                {tenants.map(t => {
                  const pendingValue = pendingReadings[t.id];
                  const displayReading = pendingValue !== undefined ? pendingValue : t.bills.currWaterReading;
                  const isModified = pendingValue !== undefined && pendingValue !== t.bills.currWaterReading;
                  const units = Math.max(0, displayReading - t.bills.prevWaterReading);
                  const cost = units * 150;

                  return (
                    <div key={t.id} className={`flex flex-col sm:flex-row items-center justify-between p-6 bg-neutral-50 rounded-[2.5rem] border transition-all ${isModified ? 'border-royal-500 ring-2 ring-royal-500/10' : 'border-neutral-100 hover:border-royal-200'}`}>
                      <div className="flex-1 mb-4 sm:mb-0">
                        <div className="font-black text-neutral-400 text-[10px] uppercase tracking-widest mb-1 flex items-center gap-2">
                          Unit {t.houseNumber} 
                          <span className="w-1 h-1 bg-neutral-300 rounded-full" /> 
                          Prev: {t.bills.prevWaterReading}
                        </div>
                        <div className="font-bold text-neutral-800 text-lg">{t.name}</div>
                        <div className="mt-1 flex items-center gap-3">
                           <span className="text-[10px] font-bold text-cyan-600 uppercase">Used: {units} units</span>
                           <span className="text-[10px] font-black text-neutral-900 uppercase">Bill: KES {cost.toLocaleString()}</span>
                        </div>
                      </div>

                      <div className="flex items-center gap-3">
                        <div className="relative">
                          <input 
                            type="number" 
                            className={`w-32 p-4 text-center text-lg font-black border-2 rounded-2xl outline-none transition-all ${updatedTenantId === t.id ? 'border-green-500 bg-green-50' : isModified ? 'border-royal-300 bg-white' : 'border-neutral-200 bg-white'}`}
                            value={displayReading}
                            onChange={(e) => setPendingReadings(prev => ({ ...prev, [t.id]: Number(e.target.value) }))}
                          />
                          <span className="absolute -top-3 left-4 bg-white px-2 text-[8px] font-black text-neutral-400 uppercase">Reading</span>
                        </div>

                        {isModified ? (
                          <button 
                            onClick={() => handleApplyUpdate(t.id)}
                            className="p-4 bg-royal-500 text-white rounded-2xl shadow-lg shadow-royal-500/20 hover:bg-royal-600 active:scale-90 transition-all group"
                          >
                            <Check size={20} strokeWidth={3} className="group-hover:scale-110" />
                          </button>
                        ) : updatedTenantId === t.id ? (
                          <div className="p-4 bg-green-500 text-white rounded-2xl shadow-lg shadow-green-500/20 animate-bounce">
                            <Save size={20} />
