                        ) : (
                          <div className="p-4 bg-neutral-200 text-neutral-400 rounded-2xl cursor-not-allowed">
                            <Check size={20} />
                          </div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
              <div className="flex flex-col gap-6 mb-8">
                <h3 className="text-xl font-bold flex items-center gap-3"><History className="text-royal-500" /> Collection Logs</h3>

                <div className="bg-neutral-50 p-6 rounded-[2rem] border border-neutral-100 grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-neutral-400 uppercase tracking-widest pl-1">Method & Category</label>
                    <div className="flex gap-2">
                      <select 
                        value={billFilterMethod}
                        onChange={(e) => setBillFilterMethod(e.target.value)}
                        className="flex-1 bg-white border border-neutral-200 rounded-lg px-2 py-2 text-[10px] font-bold outline-none"
                      >
                        <option value="ALL">All Methods</option>
                        <option value="M-Pesa">M-Pesa</option>
                        <option value="Bank">Bank</option>
                      </select>
                      <select 
                        value={billFilterType}
                        onChange={(e) => setBillFilterType(e.target.value)}
                        className="flex-1 bg-white border border-neutral-200 rounded-lg px-2 py-2 text-[10px] font-bold outline-none"
                      >
                        <option value="ALL">All Types</option>
                        <option value="RENT">Rent</option>
                        <option value="WATER">Water</option>
                      </select>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-neutral-400 uppercase tracking-widest pl-1">Date Period</label>
                    <div className="flex gap-2">
                      <input type="date" value={billStartDate} onChange={e => setBillStartDate(e.target.value)} className="flex-1 bg-white border border-neutral-200 rounded-lg px-2 py-2 text-[10px] font-bold outline-none" />
                      <button onClick={resetBillFilters} className="bg-neutral-200 hover:bg-neutral-300 p-2 rounded-lg text-neutral-500 transition-all"><RotateCcw size={14}/></button>
                    </div>
                  </div>
                </div>
              </div>

              <div className="space-y-4 max-h-[400px] overflow-y-auto scrollbar-hide">
                {filteredCollections.length === 0 ? (
                  <div className="py-20 text-center text-neutral-300 text-xs italic">No collections found matching filters.</div>
                ) : (
                  filteredCollections.map(p => {
                    const tenant = tenants.find(t => t.id === p.tenantId);
                    return (
                      <div key={p.id} className="flex items-center justify-between p-5 bg-neutral-50 rounded-2xl border border-neutral-100 hover:border-royal-200 transition-all">
                        <div className="flex items-center gap-4">
