}

export const CaretakerDashboard: React.FC<Props> = ({ 
  tenants, houses, payments, onAddTenant, onUpdateBills, onUpdateHouse,
  activeTab: propTab 
}) => {
  const [activeTab, setActiveTab] = useState<'houses' | 'tenants' | 'billing'>('houses');
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedHouse, setSelectedHouse] = useState<House | null>(null);
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [loadingAI, setLoadingAI] = useState<string | null>(null);
  const [updatedTenantId, setUpdatedTenantId] = useState<string | null>(null);

  const [pendingReadings, setPendingReadings] = useState<Record<string, number>>({});

  const [billFilterType, setBillFilterType] = useState<string>('ALL');
  const [billFilterMethod, setBillFilterMethod] = useState<string>('ALL');
  const [billStartDate, setBillStartDate] = useState<string>('');
  const [billEndDate, setBillEndDate] = useState<string>('');

  useEffect(() => {
    if (propTab) {
      if (propTab === 'houses' || propTab === 'properties') setActiveTab('houses');
      else if (propTab === 'tenants') setActiveTab('tenants');
      else if (propTab === 'billing' || propTab === 'payments') setActiveTab('billing');
    }
  }, [propTab]);

  const [newTenant, setNewTenant] = useState({
    name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0
  });

  const filteredCollections = useMemo(() => {
    return payments.filter(p => {
      const matchesType = billFilterType === 'ALL' || p.type === billFilterType;
      const matchesMethod = billFilterMethod === 'ALL' || p.method === billFilterMethod;
      const paymentDate = new Date(p.date).getTime();
      const start = billStartDate ? new Date(billStartDate).getTime() : 0;
      const end = billEndDate ? new Date(billEndDate).getTime() : Infinity;
      const matchesDate = paymentDate >= start && paymentDate <= (end + 86400000);
      return matchesType && matchesMethod && matchesDate;
    });
  }, [payments, billFilterType, billFilterMethod, billStartDate, billEndDate]);

  const handleSendReminder = async (tenant: Tenant) => {
    setLoadingAI(tenant.id);
    try {
      const message = await generateTenantNotification(tenant.name, tenant.bills.total);
      alert(`AI Reminder for ${tenant.name}:\n\n"${message}"\n\nNotification sent to ${tenant.phoneNumber}`);
    } catch (err) { console.error(err); }
    finally { setLoadingAI(null); }
  };

  const handleRegisterTenant = (e: React.FormEvent) => {
    e.preventDefault();
    const tenant: Tenant = {
      id: `t-${Date.now()}`,
      name: newTenant.name,
      email: newTenant.email,
      houseNumber: newTenant.houseNumber,
      idNumber: newTenant.idNumber,
      phoneNumber: newTenant.phoneNumber,
      nextOfKin: newTenant.nextOfKin,
      joinDate: new Date().toISOString().split('T')[0],
      bills: { 
        rent: newTenant.rent, 
        water: 0, 
        prevWaterReading: 0,
        currWaterReading: 0,
        garbage: 500, 
        total: newTenant.rent + 500, 
        status: 'UNPAID' 
      }
    };
    onAddTenant(tenant);
    setShowAddModal(false);
    setNewTenant({ name: '', email: '', houseNumber: '', idNumber: '', phoneNumber: '', nextOfKin: '', rent: 0 });
  };

  const handleApplyUpdate = (tenantId: string) => {
    const reading = pendingReadings[tenantId];
    if (reading === undefined) return;
    onUpdateBills(tenantId, reading);
    setUpdatedTenantId(tenantId);
    setPendingReadings(prev => {
      const next = { ...prev };
      delete next[tenantId];
      return next;
    });
    setTimeout(() => setUpdatedTenantId(null), 2000);
  };

  const resetBillFilters = () => {
    setBillFilterType('ALL');
    setBillFilterMethod('ALL');
    setStartDate('');
    setEndDate('');
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {showAddModal && <AddTenantModal houses={houses} newTenant={newTenant} setNewTenant={setNewTenant} onClose={() => setShowAddModal(false)} onSubmit={handleRegisterTenant} />}
      {selectedHouse && (
        <HouseDetailModal 
          house={selectedHouse} 
          onClose={() => setSelectedHouse(null)} 
          currentTenant={tenants.find(t => t.houseNumber === selectedHouse.houseNumber)} 
          onViewTenant={(t) => {
            setSelectedHouse(null);
            setSelectedTenant(t);
          }}
        />
      )}
      {selectedTenant && <TenantIntelligenceModal tenant={selectedTenant} payments={payments.filter(p => p.tenantId === selectedTenant.id)} onClose={() => setSelectedTenant(null)} onNotify={() => handleSendReminder(selectedTenant)} />}

      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-royal text-neutral-900 font-bold">Caretaker Operations</h2>
          <p className="text-neutral-400 text-sm mt-1">Daily unit management and property logistics</p>
        </div>
        <div className="flex bg-neutral-100 p-1.5 rounded-2xl border border-neutral-200 shadow-sm">
          {(['houses', 'tenants', 'billing'] as const).map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-white text-royal-500 shadow-sm' : 'text-neutral-400 hover:text-neutral-600'}`}>
              {tab === 'houses' ? 'Properties' : tab === 'billing' ? 'Collections' : tab.charAt(0).toUpperCase() + tab.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'houses' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {houses.map(house => (
            <UnitCard key={house.id} house={house} onUpdate={onUpdateHouse} onView={() => setSelectedHouse(house)} />
          ))}
          <button onClick={() => setShowAddModal(true)} className="border-2 border-dashed border-neutral-200 rounded-[2.5rem] flex flex-col items-center justify-center p-12 text-neutral-400 hover:border-royal-400 hover:text-royal-500 hover:bg-royal-50 transition-all group min-h-[300px] shadow-sm">
            <div className="bg-neutral-50 group-hover:bg-royal-100 p-6 rounded-3xl mb-4 transition-colors"><UserPlus size={40} /></div>
            <span className="font-black text-xs uppercase tracking-widest">Register Resident</span>
          </button>
        </div>
      )}

      {activeTab === 'tenants' && (
        <div className="bg-white rounded-[2.5rem] border border-neutral-200 shadow-sm overflow-hidden animate-slideUp">
          <div className="p-8 border-b border-neutral-100 flex justify-between items-center">
             <h3 className="font-bold text-lg text-neutral-800">Resident Registry</h3>
             <div className="relative">
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400" />
                <input type="text" placeholder="Search residents..." className="pl-9 pr-4 py-2 bg-neutral-50 border border-neutral-200 rounded-xl text-xs outline-none focus:border-royal-500 transition-all" />
             </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-neutral-50 border-b">
                <tr>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Resident</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Unit No</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Last Payment</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest">Bill Status</th>
                  <th className="px-8 py-5 text-[10px] font-black text-neutral-400 uppercase tracking-widest text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-neutral-50">
                {tenants.map(t => {
                  const tPayments = payments.filter(p => p.tenantId === t.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
                  const lastPayment = tPayments[0];

                  return (
                    <tr key={t.id} className="hover:bg-neutral-50 transition-all group">
                      <td className="px-8 py-6">
                        <div className="font-bold text-neutral-800 group-hover:text-royal-500 transition-colors">{t.name}</div>
                        <div className="text-[10px] text-neutral-400 font-medium tracking-tight flex items-center gap-1"><Phone size={10}/> {t.phoneNumber}</div>
                      </td>
                      <td className="px-8 py-6 font-bold text-neutral-600">{t.houseNumber}</td>
                      <td className="px-8 py-6">
                        {lastPayment ? (
                          <div>
                            <div className="text-xs font-black text-neutral-800">KES {lastPayment.amount.toLocaleString()}</div>
                            <div className="text-[9px] text-neutral-400 font-bold uppercase">{new Date(lastPayment.date).toLocaleDateString()}</div>
                          </div>
                        ) : (
                          <span className="text-[10px] text-neutral-300 italic font-medium">No records</span>
                        )}
                      </td>
                      <td className="px-8 py-6"><BillStatusBadge status={t.bills.status} /></td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex justify-end gap-3">
                          <button onClick={() => setSelectedTenant(t)} className="p-2.5 bg-neutral-100 hover:bg-neutral-200 text-neutral-500 rounded-xl transition-all"><Eye size={16} /></button>
                          <button onClick={() => handleSendReminder(t)} disabled={loadingAI === t.id} className="inline-flex items-center gap-2 bg-royal-500 hover:bg-royal-600 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-royal-500/20 disabled:opacity-50 active:scale-95 transition-all">
                            {loadingAI === t.id ? <Activity className="animate-spin" size={14}/> : <Send size={14}/>} Notify
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'billing' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          <div className="space-y-8">
            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
              <div className="flex items-center justify-between mb-8">
                <h3 className="text-xl font-bold flex items-center gap-3"><Droplets className="text-cyan-500" /> Utility Meters</h3>
                <span className="bg-cyan-50 text-cyan-600 text-[10px] font-black px-3 py-1.5 rounded-lg border border-cyan-100 uppercase tracking-widest">Rate: 150/unit</span>
              </div>

              <div className="space-y-4">
                {tenants.map(t => {
                  const pendingValue = pendingReadings[t.id];
                  const displayReading = pendingValue !== undefined ? pendingValue : t.bills.currWaterReading;
                  const isModified = pendingValue !== undefined && pendingValue !== t.bills.currWaterReading;
                  const units = Math.max(0, displayReading - t.bills.prevWaterReading);
                  const cost = units * 150;

                  return (
                    <div key={t.id} className={`flex flex-col sm:flex-row items-center justify-between p-6 bg-neutral-50 rounded-[2.5rem] border transition-all ${isModified ? 'border-royal-500 ring-2 ring-royal-500/10' : 'border-neutral-100 hover:border-royal-200'}`}>
                      <div className="flex-1 mb-4 sm:mb-0">
                        <div className="font-black text-neutral-400 text-[10px] uppercase tracking-widest mb-1 flex items-center gap-2">
                          Unit {t.houseNumber} 
                          <span className="w-1 h-1 bg-neutral-300 rounded-full" /> 
                          Prev: {t.bills.prevWaterReading}
                        </div>
                        <div className="font-bold text-neutral-800 text-lg">{t.name}</div>
                        <div className="mt-1 flex items-center gap-3">
                           <span className="text-[10px] font-bold text-cyan-600 uppercase">Used: {units} units</span>
                           <span className="text-[10px] font-black text-neutral-900 uppercase">Bill: KES {cost.toLocaleString()}</span>
                        </div>
                      </div>

                      <div className="flex items-center gap-3">
                        <div className="relative">
                          <input 
                            type="number" 
                            className={`w-32 p-4 text-center text-lg font-black border-2 rounded-2xl outline-none transition-all ${updatedTenantId === t.id ? 'border-green-500 bg-green-50' : isModified ? 'border-royal-300 bg-white' : 'border-neutral-200 bg-white'}`}
                            value={displayReading}
                            onChange={(e) => setPendingReadings(prev => ({ ...prev, [t.id]: Number(e.target.value) }))}
                          />
                          <span className="absolute -top-3 left-4 bg-white px-2 text-[8px] font-black text-neutral-400 uppercase">Reading</span>
                        </div>

                        {isModified ? (
                          <button 
                            onClick={() => handleApplyUpdate(t.id)}
                            className="p-4 bg-royal-500 text-white rounded-2xl shadow-lg shadow-royal-500/20 hover:bg-royal-600 active:scale-90 transition-all group"
                          >
                            <Check size={20} strokeWidth={3} className="group-hover:scale-110" />
                          </button>
                        ) : updatedTenantId === t.id ? (
                          <div className="p-4 bg-green-500 text-white rounded-2xl shadow-lg shadow-green-500/30 animate-bounce">
                            <Save size={20} />
                          </div>
                        ) : (
                          <div className="p-4 bg-neutral-200 text-neutral-400 rounded-2xl cursor-not-allowed">
                            <Check size={20} />
                          </div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm overflow-hidden">
              <div className="flex flex-col gap-6 mb-8">
                <h3 className="text-xl font-bold flex items-center gap-3"><History className="text-royal-500" /> Collection Logs</h3>

                <div className="bg-neutral-50 p-6 rounded-[2rem] border border-neutral-100 grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-neutral-400 uppercase tracking-widest pl-1">Method & Category</label>
                    <div className="flex gap-2">
                      <select 
                        value={billFilterMethod}
                        onChange={(e) => setBillFilterMethod(e.target.value)}
                        className="flex-1 bg-white border border-neutral-200 rounded-lg px-2 py-2 text-[10px] font-bold outline-none"
                      >
                        <option value="ALL">All Methods</option>
                        <option value="M-Pesa">M-Pesa</option>
                        <option value="Bank">Bank</option>
                      </select>
                      <select 
                        value={billFilterType}
                        onChange={(e) => setBillFilterType(e.target.value)}
                        className="flex-1 bg-white border border-neutral-200 rounded-lg px-2 py-2 text-[10px] font-bold outline-none"
                      >
                        <option value="ALL">All Types</option>
                        <option value="RENT">Rent</option>
                        <option value="WATER">Water</option>
                      </select>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[8px] font-black text-neutral-400 uppercase tracking-widest pl-1">Date Period</label>
                    <div className="flex gap-2">
                      <input type="date" value={billStartDate} onChange={e => setBillStartDate(e.target.value)} className="flex-1 bg-white border border-neutral-200 rounded-lg px-2 py-2 text-[10px] font-bold outline-none" />
                      <button onClick={resetBillFilters} className="bg-neutral-200 hover:bg-neutral-300 p-2 rounded-lg text-neutral-500 transition-all"><RotateCcw size={14}/></button>
                    </div>
                  </div>
                </div>
              </div>

              <div className="space-y-4 max-h-[400px] overflow-y-auto scrollbar-hide">
                {filteredCollections.length === 0 ? (
                  <div className="py-20 text-center text-neutral-300 text-xs italic">No collections found matching filters.</div>
                ) : (
                  filteredCollections.map(p => {
                    const tenant = tenants.find(t => t.id === p.tenantId);
                    return (
                      <div key={p.id} className="flex items-center justify-between p-5 bg-neutral-50 rounded-2xl border border-neutral-100 hover:border-royal-200 transition-all">
                        <div className="flex items-center gap-4">
                          <div className="p-2.5 bg-white rounded-xl text-green-500 shadow-sm border border-neutral-100"><Smartphone size={16}/></div>
                          <div>
                            <div className="font-bold text-neutral-800 text-sm">{tenant?.name || 'Unknown'}</div>
                            <div className="text-[9px] text-neutral-400 font-black uppercase tracking-widest">Unit {tenant?.houseNumber} • {p.type} • {new Date(p.date).toLocaleDateString()}</div>
                          </div>
                        </div>
                        <div className="text-right">
                          <div className="font-black text-neutral-900">KES {p.amount.toLocaleString()}</div>
                          <div className="text-[8px] text-neutral-400 font-mono">{p.reference}</div>
                        </div>
                      </div>
                    );
                  })
                )}
              </div>
            </div>
          </div>

          <div className="bg-neutral-900 text-white p-10 rounded-[3rem] shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-10 opacity-0 group-hover:opacity-10 transition-opacity duration-700 text-royal-500"><Wrench size={160} /></div>
            <h3 className="text-xl font-bold mb-8 flex items-center gap-3 font-royal text-royal-100"><RefreshCw className="text-royal-500" /> Maintenance Logs</h3>
            <div className="space-y-4 max-h-[600px] overflow-y-auto scrollbar-hide">
              <MaintenanceItem date="Today" task="Front Gate Calibration" cost={4500} house="External" />
              <MaintenanceItem date="Yesterday" task="Kitchen Sink B4 Repair" cost={8200} house="B4" />
              <MaintenanceItem date="12th Sep" task="Corridor Lighting" cost={1500} house="Common Areas" />
              <MaintenanceItem date="05th Sep" task="Rooftop Tank Cleaning" cost={25000} house="Common Areas" />
            </div>
            <button className="w-full mt-10 bg-royal-500 text-white py-5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-royal-600 shadow-xl shadow-royal-500/20 active:scale-95 transition-all">Log Maintenance Event</button>
          </div>
        </div>
      )}
    </div>
  );
};

const UnitCard: React.FC<{ house: House, onUpdate: any, onView: any }> = ({ house, onUpdate, onView }) => {
  const isRented = house.status === HouseStatus.RENTED;
  const isVacant = house.status === HouseStatus.VACANT;
  const borderClass = isRented ? 'border-green-100 hover:border-green-300' : isVacant ? 'border-amber-100 hover:border-amber-300' : 'border-red-100 hover:border-red-300';
  const accentClass = isRented ? 'bg-green-500' : isVacant ? 'bg-amber-500' : 'bg-red-500';

  return (
    <div className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all group relative overflow-hidden flex flex-col shadow-sm hover:shadow-xl hover:shadow-neutral-200/50 ${borderClass}`}>
      <div className={`absolute top-0 left-0 right-0 h-1.5 ${accentClass}`} />
      <div className="flex justify-between items-start mb-10">
        <div>
          <h3 className="text-3xl font-royal font-black text-neutral-800 tracking-tighter">{house.houseNumber}</h3>
          <p className="text-[10px] text-neutral-400 font-black uppercase tracking-widest mt-1.5">{house.type}</p>
        </div>
        <div className="flex flex-col items-end gap-2">
          <StatusBadge status={house.status} />
          <button onClick={onView} className="p-2.5 bg-neutral-50 hover:bg-neutral-200 text-neutral-500 rounded-xl transition-all border border-neutral-100"><Eye size={16} /></button>
        </div>
      </div>
      <div className="space-y-4 mb-10 flex-1">
        <div className="bg-neutral-50 p-4 rounded-2xl border border-neutral-100 flex justify-between items-center transition-all group-hover:bg-white group-hover:shadow-sm">
           <span className="text-[10px] text-neutral-400 font-black uppercase tracking-widest">Lifetime Yield</span>
           <span className="font-black text-neutral-900 tracking-tight">KES {house.totalEarnings.toLocaleString()}</span>
        </div>
        <div className="flex justify-between text-xs items-center px-1"><span className="text-neutral-400 font-bold uppercase tracking-tight">Service Logs</span><span className="font-black text-amber-600">{house.repairs.length} Records</span></div>
      </div>
      <div className="grid grid-cols-3 gap-1.5 bg-neutral-100/80 p-1.5 rounded-2xl border border-neutral-200">
        <UnitStatusBtn active={house.status === HouseStatus.RENTED} onClick={() => onUpdate(house.id, HouseStatus.RENTED)} color="green" label="Rented" icon={<CheckCircle2 size={12}/>} />
        <UnitStatusBtn active={house.status === HouseStatus.VACANT} onClick={() => onUpdate(house.id, HouseStatus.VACANT)} color="amber" label="Vacant" icon={<CircleDashed size={12}/>} />
        <UnitStatusBtn active={house.status === HouseStatus.UNDER_REPAIR} onClick={() => onUpdate(house.id, HouseStatus.UNDER_REPAIR)} color="red" label="Repair" icon={<Hammer size={12}/>} />
      </div>
    </div>
  );
};

const UnitStatusBtn: React.FC<{ active: boolean, onClick: () => void, color: 'green' | 'amber' | 'red', label: string, icon: React.ReactNode }> = ({ active, onClick, color, label, icon }) => {
  const variants = {
    green: active ? 'bg-green-500 text-white shadow-lg shadow-green-500/20' : 'text-neutral-400 hover:text-green-600 hover:bg-green-50',
    amber: active ? 'bg-amber-500 text-white shadow-lg shadow-amber-500/20' : 'text-neutral-400 hover:text-amber-600 hover:bg-amber-50',
    red: active ? 'bg-red-500 text-white shadow-lg shadow-red-500/20' : 'text-neutral-400 hover:text-red-600 hover:bg-red-50',
  };
  return <button onClick={onClick} className={`flex flex-col items-center justify-center py-3 rounded-xl transition-all gap-1 ${variants[color]}`}>{icon}<span className="text-[8px] font-black uppercase tracking-tight">{label}</span></button>;
};

const AddTenantModal: React.FC<{ houses: House[], newTenant: any, setNewTenant: any, onClose: () => void, onSubmit: any }> = ({ houses, newTenant, setNewTenant, onClose, onSubmit }) => (
  <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-neutral-900/90 backdrop-blur-sm animate-fadeIn">
    <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden animate-slideUp">
      <div className="bg-royal-500 p-10 text-white flex justify-between items-center relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-10"><UserPlus size={100}/></div>
        <div className="relative z-10">
           <h3 className="text-3xl font-royal font-black tracking-tight">Tenant Onboarding</h3>
           <p className="text-royal-100 text-xs uppercase font-black tracking-widest mt-1">Official Registry Entry</p>
        </div>
        <button onClick={onClose} className="p-4 bg-white/10 hover:bg-white/20 rounded-2xl transition-all"><X size={24} /></button>
      </div>
      <form onSubmit={onSubmit} className="p-12 grid grid-cols-1 md:grid-cols-2 gap-8">
        <InputGroup icon={<User size={16}/>} label="Full Name" placeholder="Michael Omondi" value={newTenant.name} onChange={(val) => setNewTenant({...newTenant, name: val})} />
        <InputGroup icon={<Hash size={16}/>} label="ID Number" placeholder="34567890" value={newTenant.idNumber} onChange={(val) => setNewTenant({...newTenant, idNumber: val})} />
        <InputGroup icon={<Phone size={16}/>} label="Phone Number" placeholder="0712345678" value={newTenant.phoneNumber} onChange={(val) => setNewTenant({...newTenant, phoneNumber: val})} />
        <InputGroup icon={<Users size={16}/>} label="Next of Kin" placeholder="Full Name & Contact" value={newTenant.nextOfKin} onChange={(val) => setNewTenant({...newTenant, nextOfKin: val})} />
        <div className="space-y-2">
          <label className="text-[10px] font-black text-neutral-400 uppercase tracking-widest flex items-center gap-2"><MapPin size={14}/> Unit Assignment</label>
          <select required className="w-full bg-neutral-50 border-2 border-neutral-100 p-4 rounded-2xl focus:border-royal-500 outline-none transition-all text-sm font-bold text-neutral-700" value={newTenant.houseNumber} onChange={(e) => setNewTenant({...newTenant, houseNumber: e.target.value})}>
            <option value="">Select Suite</option>
            {houses.map(h => <option key={h.id} value={h.houseNumber} disabled={h.status === HouseStatus.RENTED}>{h.houseNumber} - {h.type}</option>)}
          </select>
        </div>
