import React, { useState, useMemo, useEffect } from 'react';
import { Tenant, PaymentRecord, Incident } from '../types';
import { 
  CreditCard, History, Phone, MessageSquare, CheckCircle, Wallet, Mail, 
  Home, Calendar, ChevronDown, AlertTriangle, X, ShieldCheck, ArrowUpRight, Check,
  Smartphone, Hash, Download, Receipt, User, FileText, Shield, MapPin, ExternalLink,
  Users, ArrowRight, Filter, Search, RotateCcw, Landmark, PiggyBank, Info,
  AlertCircle, ShieldAlert, FileClock, Wrench, Crown, Activity, Droplets
} from 'lucide-react';

interface Props {
  tenant: Tenant;
  payments: PaymentRecord[];
  onPay: (payment: PaymentRecord) => void;
  initialTab?: 'payments' | 'profile';
}

type TenantTab = 'payments' | 'profile';

export const TenantDashboard: React.FC<Props> = ({ tenant, payments, onPay, initialTab = 'profile' }) => {
  const [activeTab, setActiveTab] = useState<TenantTab>(initialTab);
  const [isPaying, setIsPaying] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [billType, setBillType] = useState<PaymentRecord['type']>('TOTAL');
  const [paymentAmount, setPaymentAmount] = useState(tenant.bills.total);

  useEffect(() => {
    setActiveTab(initialTab);
  }, [initialTab]);

  const totalLifetimePaid = useMemo(() => {
    return payments.reduce((acc, p) => acc + p.amount, 0);
  }, [payments]);

  const [filterType, setFilterType] = useState<string>('ALL');
  const [filterMethod, setFilterMethod] = useState<string>('ALL');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  const filteredPayments = useMemo(() => {
    return payments.filter(p => {
      const matchesType = filterType === 'ALL' || p.type === filterType;
      const matchesMethod = filterMethod === 'ALL' || p.method === filterMethod;
      const paymentDate = new Date(p.date).getTime();
      const start = startDate ? new Date(startDate).getTime() : 0;
      const end = endDate ? new Date(endDate).getTime() : Infinity;
      const matchesDate = paymentDate >= start && paymentDate <= (end + 86400000);
      return matchesType && matchesMethod && matchesDate;
    });
  }, [payments, filterType, filterMethod, startDate, endDate]);

  const handleBillTypeChange = (type: PaymentRecord['type']) => {
    setBillType(type);
    if (type === 'RENT') setPaymentAmount(tenant.bills.rent);
    else if (type === 'WATER') setPaymentAmount(tenant.bills.water);
    else if (type === 'GARBAGE') setPaymentAmount(tenant.bills.garbage);
    else setPaymentAmount(tenant.bills.total);
  };

  const handleInitiatePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (paymentAmount > 0) setShowConfirm(true);
  };

  const resetFilters = () => {
    setFilterType('ALL');
    setFilterMethod('ALL');
    setStartDate('');
    setEndDate('');
  };

  const simulatePayment = () => {
    setShowConfirm(false);
    setIsPaying(true);
    setTimeout(() => {
      onPay({
        id: `pay-${Date.now()}`,
        tenantId: tenant.id,
        amount: paymentAmount,
        date: new Date().toISOString(),
        type: billType,
