          <button type="submit" className="flex-[2] py-5 rounded-2xl font-black text-xs uppercase tracking-widest text-white bg-royal-500 hover:bg-royal-600 shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-2">Finalize Onboarding <ArrowRight size={16}/></button>
        </div>
      </form>
    </div>
  </div>
);

