                     </tr>
                   </thead>
                   <tbody className="divide-y divide-neutral-50">
                     {filteredPayments.map(p => (
                       <tr key={p.id} className="hover:bg-neutral-50/50 transition-colors">
                         <td className="px-6 py-5">
                            <div className="text-xs font-bold text-neutral-800">{new Date(p.date).toLocaleDateString()}</div>
                            <div className="text-[9px] text-neutral-400 uppercase font-black">{p.type}</div>
                         </td>
                         <td className="px-6 py-5 font-mono text-[10px] text-neutral-400 uppercase">{p.reference}</td>
                         <td className="px-6 py-5 text-right font-black text-neutral-900 tracking-tighter">KES {p.amount.toLocaleString()}</td>
                       </tr>
                     ))}
                     {filteredPayments.length === 0 && <tr><td colSpan={3} className="py-20 text-center text-neutral-300 italic text-sm">No matched records.</td></tr>}
                   </tbody>
                 </table>
               </div>
            </div>
          </div>

          <div className="bg-neutral-900 text-white p-10 rounded-[3.5rem] shadow-2xl relative overflow-hidden flex flex-col justify-between h-[600px] border border-neutral-800 group sticky top-8">
             <div className="absolute top-0 right-0 p-10 opacity-0 group-hover:opacity-10 transition-opacity duration-700 text-royal-500"><CreditCard size={180} /></div>
             <div className="relative z-10">
                <div className="flex items-center gap-3 mb-10">
                   <div className="w-12 h-12 bg-royal-500 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-royal-500/20"><Wallet size={24}/></div>
                   <div>
                      <h3 className="text-xl font-royal text-royal-100 font-black tracking-tight">Lipa Na M-Pesa</h3>
                      <p className="text-[8px] font-black text-neutral-500 uppercase tracking-widest">Instant STK Protocol</p>
                   </div>
                </div>

                <form onSubmit={handleInitiatePayment} className="space-y-8">
                  <div className="space-y-2">
                    <label className="text-[10px] text-neutral-500 font-black uppercase tracking-widest pl-1 block">Allocation Category</label>
                    <div className="relative">
                       <select value={billType} onChange={(e) => handleBillTypeChange(e.target.value as PaymentRecord['type'])} className="appearance-none bg-neutral-800 border border-neutral-700 w-full p-5 rounded-2xl text-royal-100 font-bold outline-none focus:border-royal-500 transition-all">
                        <option value="TOTAL">Balance Payout</option>
                        <option value="RENT">Rent Component</option>
                        <option value="WATER">Water Utility</option>
                        <option value="GARBAGE">Service Fee</option>
                      </select>
                      <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-neutral-500 pointer-events-none" size={20} />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] text-neutral-500 font-black uppercase tracking-widest pl-1 block">Volume (KES)</label>
                    <input type="number" value={paymentAmount} onChange={(e) => setPaymentAmount(Number(e.target.value))} className="bg-neutral-800 border border-neutral-700 w-full p-5 rounded-2xl text-royal-500 font-black text-3xl outline-none focus:border-royal-500 transition-all tracking-tighter" required min="1" />
                  </div>
                  <button type="submit" disabled={isPaying || paymentAmount <= 0} className="w-full bg-[#32ba43] hover:bg-[#2da33b] disabled:opacity-50 text-white font-black text-xs uppercase tracking-[0.2em] py-6 rounded-2xl shadow-2xl transition-all active:scale-95">
                    {isPaying ? 'CONNECTING...' : 'INITIATE STK PUSH'}
                  </button>
                </form>
             </div>
             <div className="pt-10 border-t border-neutral-800 text-center relative z-10 text-[8px] text-neutral-600 font-black uppercase tracking-widest">
                Daraja API Gateway Secured
             </div>
          </div>
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-10 animate-slideUp">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-1 space-y-8">
               <div className="bg-neutral-900 text-white p-10 rounded-[3rem] shadow-2xl relative overflow-hidden flex flex-col items-center text-center group">
                 <div className="absolute top-0 right-0 p-8 opacity-5 text-royal-500"><Crown size={120} /></div>
                 <div className="w-32 h-32 bg-neutral-800 rounded-[2.5rem] flex items-center justify-center border-4 border-royal-500/20 text-royal-400 mb-8 shadow-2xl group-hover:scale-105 transition-transform duration-500">
                    <User size={64} />
                 </div>
                 <span className="bg-royal-500/20 text-royal-300 text-[8px] font-black uppercase tracking-[0.4em] px-4 py-1.5 rounded-full mb-4 border border-royal-500/30">Verified Resident</span>
                 <h3 className="text-3xl font-royal font-black text-royal-100 mb-2">{tenant.name}</h3>
                 <p className="text-neutral-500 text-xs font-bold uppercase tracking-widest">Unit {tenant.houseNumber} • Since {tenant.joinDate}</p>

                 <div className="w-full mt-10 pt-10 border-t border-white/5 space-y-4">
                    <ProfileLink icon={<Phone size={14}/>} label="Phone" value={tenant.phoneNumber} />
                    <ProfileLink icon={<Mail size={14}/>} label="Email" value={tenant.email} />
                    <ProfileLink icon={<Shield size={14}/>} label="KYC ID" value={`****${tenant.idNumber.slice(-4)}`} />
                 </div>
               </div>

               <div className="bg-white p-8 rounded-[2.5rem] border border-neutral-200 shadow-sm">
                  <h4 className="text-[10px] font-black uppercase tracking-widest text-neutral-400 mb-6 flex items-center gap-2"><Droplets size={14} className="text-cyan-500" /> Utility Usage</h4>
                  <div className="flex justify-between items-end mb-4">
                     <div>
                       <div className="text-2xl font-black text-neutral-800">{tenant.bills.currWaterReading} <span className="text-xs text-neutral-400">units</span></div>
                       <p className="text-[9px] font-black text-neutral-400 uppercase mt-1">Current Meter Reading</p>
                     </div>
                     <div className="text-right">
                       <div className="text-lg font-bold text-cyan-600">KES {tenant.bills.water.toLocaleString()}</div>
                       <p className="text-[9px] font-black text-neutral-400 uppercase mt-1">Bill Amount</p>
                     </div>
                  </div>
                  <div className="h-2 w-full bg-neutral-100 rounded-full overflow-hidden">
                     <div className="h-full bg-cyan-500 rounded-full" style={{ width: '65%' }} />
                  </div>
               </div>
            </div>

            <div className="lg:col-span-2 space-y-8">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
                 <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-10 opacity-5 text-royal-500"><FileText size={140} /></div>
                    <span className="text-neutral-400 text-[9px] font-black uppercase tracking-widest block mb-8">Lease & Security</span>
                    <div className="flex items-center gap-4 mb-8">
                       <div className="p-4 bg-royal-50 rounded-2xl text-royal-500 border border-royal-100"><Home size={28}/></div>
                       <div>
                          <h4 className="text-xl font-bold text-neutral-800">Premium Suite</h4>
                          <p className="text-xs text-neutral-400 font-bold uppercase tracking-tight">Active Occupancy</p>
                       </div>
                    </div>
                    <div className="space-y-4">
                       <LeaseData label="Maturity Date" value="Oct 14, 2025" />
                       <LeaseData label="Held Deposit" value={`KES ${tenant.lease?.depositAmount.toLocaleString() || 'Verified'}`} />
                       <LeaseData label="Notice Period" value="30 Days" />
                    </div>
                    <button className="w-full mt-10 py-4 bg-neutral-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl active:scale-95 transition-all">Download Contract</button>
                 </div>

                 <div className="bg-white p-10 rounded-[3rem] border border-neutral-200 shadow-sm relative overflow-hidden">
                    <span className="text-neutral-400 text-[9px] font-black uppercase tracking-widest block mb-8">Lifetime Vitality</span>
                    <div className="flex items-center gap-4 mb-8 text-green-500">
                       <div className="p-4 bg-green-50 rounded-2xl border border-green-100"><Activity size={28}/></div>
                       <div>
                          <h4 className="text-xl font-bold text-neutral-800">Account Health</h4>
                          <p className="text-xs text-green-600 font-black uppercase tracking-tight">EXCELLENT</p>
                       </div>
                    </div>
                    <div className="space-y-4">
                       <LeaseData label="Lifetime Paid" value={`KES ${totalLifetimePaid.toLocaleString()}`} />
                       <LeaseData label="Late Payouts" value="0 Events" />
                       <LeaseData label="Support Tickets" value="2 Resolved" />
                    </div>
                    <button className="w-full mt-10 py-4 bg-royal-50 text-royal-500 rounded-2xl border border-royal-100 font-black text-[10px] uppercase tracking-widest hover:bg-royal-100 transition-all">Support Center</button>
                 </div>
              </div>

              {/* REPLACED TIMELINE WITH PAYMENT RECORDS */}
              <div className="bg-white p-12 rounded-[3.5rem] border border-neutral-200 shadow-sm">
                 <div className="flex items-center justify-between mb-10">
                    <h3 className="text-xl font-black text-neutral-800 flex items-center gap-3"><Receipt className="text-royal-500"/> Recent Payment History</h3>
                    <button onClick={() => setActiveTab('payments')} className="text-[10px] font-black uppercase text-royal-500 hover:text-royal-600 tracking-widest flex items-center gap-2 transition-all">
                       Full Statement <ArrowUpRight size={14}/>
                    </button>
                 </div>
                 <div className="space-y-4">
                    {payments.slice(0, 5).map((payment) => (
                      <div key={payment.id} className="flex items-center justify-between p-6 bg-neutral-50 rounded-[2.5rem] border border-neutral-100 hover:bg-white hover:border-royal-200 transition-all group">
                         <div className="flex items-center gap-5">
                            <div className="w-12 h-12 rounded-2xl bg-white border border-neutral-200 flex items-center justify-center text-green-500 shadow-sm group-hover:scale-110 transition-transform">
                               <ArrowDownRight size={20}/>
                            </div>
                            <div>
                               <div className="flex items-center gap-2 mb-0.5">
                                  <span className="text-[10px] font-black text-neutral-400 uppercase tracking-widest">{new Date(payment.date).toLocaleDateString()}</span>
                                  <span className="w-1 h-1 bg-neutral-300 rounded-full" />
                                  <span className="text-[9px] font-bold text-neutral-500 uppercase">{payment.method}</span>
                               </div>
                               <h5 className="font-bold text-neutral-800 text-sm">{payment.type.replace('_', ' ')} Component</h5>
                               <p className="text-neutral-400 font-mono text-[9px] mt-0.5">Ref: {payment.reference}</p>
                            </div>
                         </div>
                         <div className="text-right">
                            <div className="text-lg font-black text-neutral-900 tracking-tight">KES {payment.amount.toLocaleString()}</div>
                            <div className="text-[8px] font-black text-green-600 uppercase">Verified</div>
                         </div>
                      </div>
                    ))}
                    {payments.length === 0 && (
                      <div className="py-16 text-center border-2 border-dashed border-neutral-100 rounded-[3rem] text-neutral-300 italic text-sm">No recent transactions recorded.</div>
                    )}
                 </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// Internal Components
const ProfileLink: React.FC<{ icon: React.ReactNode, label: string, value: string }> = ({ icon, label, value }) => (
  <div className="flex justify-between items-center group/link">
    <div className="flex items-center gap-3">
       <span className="text-neutral-600 group-hover/link:text-royal-400 transition-colors">{icon}</span>
       <span className="text-[10px] font-black uppercase text-neutral-500 tracking-widest">{label}</span>
    </div>
    <span className="text-[11px] font-bold text-neutral-400 group-hover/link:text-royal-100 transition-colors">{value}</span>
  </div>
);

const LeaseData: React.FC<{ label: string, value: string }> = ({ label, value }) => (
  <div className="flex justify-between items-center py-2 border-b border-neutral-50 last:border-0">
    <span className="text-[10px] text-neutral-400 font-black uppercase tracking-widest">{label}</span>
    <span className="text-sm font-bold text-neutral-800">{value}</span>
  </div>
);

const PaymentConfirmationModal: React.FC<{ amount: number, billType: string, phone: string, onCancel: () => void, onConfirm: () => void }> = ({ amount, billType, phone, onCancel, onConfirm }) => (
  <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-neutral-900/90 backdrop-blur-sm animate-fadeIn">
    <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl overflow-hidden animate-slideUp border border-neutral-200">
      <div className="bg-[#32ba43] p-10 text-white flex justify-between items-center">
        <div>
           <h3 className="text-2xl font-royal font-black tracking-tight">Confirm Payment</h3>
           <p className="text-green-100 text-[10px] font-black uppercase tracking-widest mt-1">M-Pesa STK Push Prompt</p>
        </div>
        <button onClick={onCancel} className="p-3 bg-white/10 hover:bg-white/20 rounded-2xl"><X size={20} /></button>
      </div>
      <div className="p-10 text-center space-y-10">
        <div>
          <p className="text-neutral-400 text-[10px] uppercase font-black mb-4">Payout</p>
          <div className="text-6xl font-black text-neutral-900 tracking-tighter">KES {amount.toLocaleString()}</div>
        </div>
        <div className="bg-neutral-50 rounded-2xl p-6 space-y-3 text-sm text-left font-bold text-neutral-700">
          <div className="flex justify-between"><span>Bill:</span><span>{billType}</span></div>
          <div className="flex justify-between"><span>Phone:</span><span>{phone}</span></div>
        </div>
        <div className="flex gap-4">
          <button onClick={onCancel} className="flex-1 py-5 rounded-2xl font-black text-[10px] uppercase tracking-widest text-neutral-400 hover:bg-neutral-50 border border-neutral-100 transition-all">Cancel</button>
          <button onClick={onConfirm} className="flex-[2] bg-[#32ba43] text-white font-black text-[10px] uppercase tracking-widest py-5 rounded-2xl shadow-xl transition-all">Verify & Push</button>
        </div>
      </div>
    </div>
  </div>
);

const BillCard: React.FC<{ title: string, amount: number, icon: React.ReactNode, urgent?: boolean }> = ({ title, amount, icon, urgent }) => (
  <div className={`p-8 rounded-[2.5rem] border transition-all ${urgent ? 'bg-royal-50 border-royal-100' : 'bg-white border-neutral-100 shadow-sm'}`}>
    <div className="flex justify-between items-start mb-6">
      <span className={`text-[10px] font-black uppercase tracking-widest ${urgent ? 'text-royal-500' : 'text-neutral-400'}`}>{title}</span>
      <div className="p-2 bg-neutral-50 rounded-xl">{icon}</div>
    </div>
    <div className={`text-3xl font-bold tracking-tighter ${urgent ? 'text-royal-700' : 'text-neutral-800'}`}>
      <span className="text-sm font-medium opacity-40 mr-1.5">KES</span>
      {amount.toLocaleString()}
    </div>
  </div>
);
